    // ========================================
    // 🔮 v1.4.2-beta: QNO STORAGE INITIALIZATION
    // Persistent storage for Quantum Neural Oracle prediction staking
    // (Gated: q_storage::qno_storage not available on Windows)
    // ========================================
    #[cfg(not(target_os = "windows"))]
    {
        info!("🔮 ════════════════════════════════════════════════════════");
        info!("🔮 Initializing QNO Storage (v1.4.2-beta)...");

        // Re-obtain db handle (original `db` is scoped inside previous #[cfg] block)
        let hot_db = state.storage_engine.get_hot_db();
        let db = hot_db.db();
        let qno_storage = Arc::new(QnoStorage::new(db.clone()));

        // Initialize QNO storage (loads positions/domains from disk or creates defaults)
        match qno_storage.initialize().await {
            Ok(()) => {
                info!("✅ QNO Storage initialized successfully");

                // Store in AppState
                *state.qno_storage.write().await = Some(qno_storage.clone());

                // Start background reward accrual task
                let qno_storage_task = state.qno_storage.clone();
                qno_api::start_reward_accrual_task(qno_storage_task.clone());
                info!("✅ QNO reward accrual task started (60-second interval)");

                // Start background resolution task (v1.4.3-beta)
                qno_api::start_resolution_task(qno_storage_task);
                info!("✅ QNO resolution task started (hourly oracle check)");
            }
            Err(e) => {
                error!("❌ Failed to initialize QNO Storage: {}", e);
                error!("   QNO prediction staking will be unavailable");
                // Non-fatal: continue without QNO
            }
        }

        info!("🔮 ════════════════════════════════════════════════════════");
    }

    // ========================================
    // 🔐 v1.1.25-beta: MAINNET SAFETY INFRASTRUCTURE
    // Initialize checkpoint manager, integrity monitor, and backup system
    // ========================================
    info!("🔐 ════════════════════════════════════════════════════════");
    info!("🔐 Initializing Mainnet Safety Infrastructure...");

    // Get database path from environment or use default
    let db_path = std::env::var("Q_DB_PATH").unwrap_or_else(|_| "./data".to_string());
    let data_dir = std::path::PathBuf::from(&db_path);

    // Create directories if they don't exist
    let _ = std::fs::create_dir_all(&data_dir);

    // Initialize MainnetSafetyManager with storage engine
    // Note: MainnetSafetyManager::new is not async
    let safety_manager: std::sync::Arc<q_storage::MainnetSafetyManager> = std::sync::Arc::new(
        q_storage::MainnetSafetyManager::new(
            data_dir.clone(),
            state.storage_engine.clone(),
        )
    );

    // v10.5.0: Wire gap-fill channel so auto-repair actually fetches missing blocks.
    // The sender lives in the integrity monitor; the receiver is consumed below after
    // turbo_sync is constructed (it needs turbo_sync to dispatch the fetch).
    let (gap_fill_tx, gap_fill_rx) =
        tokio::sync::mpsc::unbounded_channel::<(u64, u64)>();
    safety_manager.integrity_monitor.set_gap_fill_channel(gap_fill_tx);

    info!("✅ MainnetSafetyManager initialized successfully");
    info!("   📍 Data directory: {}", db_path);

    // Start all safety systems (checkpoint manager, integrity monitor, backup system)
    // The start() method spawns background tasks for:
    // - Hourly auto-checkpoints with 24-hour retention
    // - 60-second integrity checks with auto-repair
    // - 6-hour incremental backups
    if let Err(e) = safety_manager.start().await {
        error!("⚠️ Failed to start safety systems: {}", e);
        // Non-fatal - continue without safety systems in dev mode
    } else {
        info!("✅ All mainnet safety background tasks started");
    }

    info!("🔐 ════════════════════════════════════════════════════════");

    // ========================================
    // 🔄 PHASE 3 BLOCK SYNC INTEGRATION
    // Integrate storage and consensus with libp2p block synchronization
    // ========================================
    // ✅ v0.9.75-beta: CRITICAL FIX - Set storage BEFORE spawning event loop to prevent deadlock
    // Old approach: Event loop spawned first → locked manager forever → Phase 3 timeouts
    // New approach: Lock manager briefly → set storage → release lock → spawn event loop
    if let Some(ref libp2p_manager) = state.libp2p_discovery {
        info!("🔄 Setting up Phase 3 libp2p block synchronization...");

        // Create block sync channel before locking
        let (block_sync_tx, mut block_sync_rx) = tokio::sync::mpsc::unbounded_channel();

        // Phase 3a & 3b: Lock manager briefly to set storage and channel
        {
            let mut manager = libp2p_manager.lock().await;

            // Phase 3a: Inject storage into network manager
            manager.set_storage(state.storage_engine.clone());
            info!("✅ Phase 3a: Storage engine linked to network manager");

            // Phase 3b: Set up consensus forwarding channel
            manager.set_block_sync_channel(block_sync_tx);
            info!("✅ Phase 3b: Block sync forwarding channel established");

            // Lock is released here when manager goes out of scope
        }

        // Phase 3c: NOW spawn event loop (after storage is configured and lock is released)
        let manager_clone = libp2p_manager.clone();
        tokio::spawn(async move {
            info!("🔄 Starting libp2p network event loop...");

            // 🚨 v1.0.17-beta CRITICAL DEADLOCK FIX:
            // DO NOT hold lock across the entire event loop (nm.run())!
            // The old code acquired lock once and held it FOREVER, blocking ALL other
            // operations that need libp2p (gap-fill sync, batch sync, auto-sync).
            //
            // ROOT CAUSE: Line 1682 acquired lock, line 1683 called nm.run() which is
            // an infinite loop that NEVER returns. This blocked gap-fill sync at line 7469,
            // batch sync at line 7398, and auto-sync at line 1877.
            //
            // FIX: Use run_once() in a loop, acquiring and releasing lock each iteration.
            // This allows other tasks to acquire the lock between iterations.
            //
            // Evidence: Single-producer test ruled out producer contention. Lock audit
            // identified this as the ONLY lock held forever.
            //
            // See: DEADLOCK_ROOT_CAUSE_FOUND_v1.0.17.md for complete analysis

            loop {
                // 🚨 v1.0.22-beta CRITICAL FIX #3: Use try_lock() to prevent tokio runtime starvation
                // Previous fix (v1.0.17-beta-v2): timeout + .lock().await
                // Problem: If all tokio threads block on .lock().await, timeout task can't run → DEADLOCK
                // Evidence: GDB showed 0 threads working, all in futex wait after ~10 min
                //
                // NEW FIX: Use try_lock() instead of .lock().await
                // Benefits:
                // - Never blocks tokio thread (returns immediately)
                // - Timeout tasks can always run
                // - Fair task scheduling with yield_now()
                // - Graceful degradation under lock contention
                //
                // See: DEADLOCK_FIX_NON_BLOCKING_LOCK_v1.0.22.md

                match manager_clone.try_lock() {
                    Ok(mut nm) => {
                        // Successfully acquired lock - process one event with timeout
                        // v10.9.36: bumped 10ms → 100ms. Per code analytics 2026-05-16:
                        // 10ms slices starve libp2p's Swarm of polling time during
                        // multi-round-trip Noise/Identify handshakes — peer mesh
                        // never forms (qnk_peers_connected stays at 0 indefinitely).
                        // 100ms still well below the "lock held forever" deadlock
                        // threshold cited in v1.0.22 (was several MINUTES). Other
                        // tasks needing the lock wait at most 100ms per iteration.
                        let result = tokio::time::timeout(
                            std::time::Duration::from_millis(100),
                            nm.run_once()
                        ).await;

                        match result {
                            Ok(Ok(())) => {
                                // Successfully processed one event
                            }
                            Ok(Err(e)) => {
                                error!("❌ Network manager event loop error: {}", e);
                            }
                            Err(_) => {
                                // Timeout - no events in 10ms
                            }
                        }

                        // Explicitly drop lock before yielding
                        drop(nm);
                    }
                    Err(_) => {
                        // Lock is held by another task - yield without logging (normal under load)
                    }
                }

                // CRITICAL: Yield to scheduler after EVERY iteration
                // This ensures other tasks (like block production) can run
                tokio::task::yield_now().await;
            }
        });

        info!("✅ libp2p network event loop spawned with storage and block sync configured");

        // v10.9.41: spawn the producer-hook task that extends the lattice tip
        // proof on every contiguous-height advance. Decoupled from save_qblock
        // (which lives in q-storage, no dep on q-recursive-proofs) — instead we
        // poll the atomic at 500ms and catch up on whatever was committed.
        // Cost in steady state: 1 BLAKE3-XOF per new block (~1 µs), so even a
        // 10-block-per-tick burst is sub-millisecond. On startup the loop walks
        // from genesis (height 0, all-zero state) up to current contiguous
        // height — for a fully-synced 18M-block chain that's ~18 s of warmup,
        // amortised once. Future v10.9.42+: persist to RocksDB so the warmup
        // is skipped on subsequent restarts.
        {
            // AppState is owned (not Arc-wrapped) at this point, so we clone just
            // the Arc'd fields the producer-hook task needs.
            let proof_slot = state.lattice_tip_proof.clone();
            let height_atomic = state.contiguous_height_atomic.clone();
            let storage = state.storage_engine.clone();
            tokio::spawn(async move {
                info!("🔐 [LATTICE-TIP] Producer-hook task starting (anchors at genesis, extends per block)");
                // v10.9.51: try to resume from persisted proof first (skips the
                // 18s warmup walk through 18M blocks on restart). If load
                // fails (no persisted proof, OR deserialise error from older
                // wire format), fall through to cold-start anchor.
                let mut current_proof = match storage.load_tip_proof_bytes().await {
                    Some(bytes) => match bincode::deserialize::<q_recursive_proofs::LatticeTipProof>(&bytes) {
                        Ok(p) => {
                            info!(
                                "🔐 [LATTICE-TIP v10.9.51] RESUMED from persisted proof at height {} (skipped warmup walk; {} bytes loaded)",
                                p.tip_height, bytes.len()
                            );
                            p
                        }
                        Err(e) => {
                            warn!(
                                "🔐 [LATTICE-TIP v10.9.51] persisted proof deserialise failed ({}) — cold-starting from anchor. Old wire format will be overwritten on next save.",
                                e
                            );
                            q_recursive_proofs::tip_anchor(0, [0u8; 32])
                        }
                    },
                    None => {
                        info!("🔐 [LATTICE-TIP v10.9.51] no persisted proof — cold-starting from anchor (first run or fresh DB)");
                        q_recursive_proofs::tip_anchor(0, [0u8; 32])
                    }
                };
                {
                    let mut guard = proof_slot.write().await;
                    *guard = Some(current_proof.clone());
                }
                let mut last_extended_height = current_proof.tip_height;
                // v10.9.51: persist every PERSIST_INTERVAL extends to bound
                // restart loss (~500 ms of extend work at typical block rate).
                const PERSIST_INTERVAL: u64 = 1_000;
                let mut extends_since_persist: u64 = 0;
                loop {
                    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
                    let contiguous = height_atomic.load(std::sync::atomic::Ordering::Relaxed);
                    if contiguous <= last_extended_height {
                        continue;
                    }
                    // Bound per-tick work so the warmup walk doesn't starve
                    // other tasks. 1000 blocks * ~1 µs/block = 1 ms per tick.
                    let target = contiguous.min(last_extended_height + 1000);
                    for h in (last_extended_height + 1)..=target {
                        match storage.get_qblock_by_height(h).await {
                            Ok(Some(block)) => {
                                current_proof = q_recursive_proofs::tip_extend(
                                    &current_proof,
                                    h,
                                    block.header.state_root,
                                    block.header.prev_block_hash,
                                    block.header.tx_root,
                                );
                                last_extended_height = h;
                                extends_since_persist += 1;
                            }
                            Ok(None) => {
                                if h % 1000 == 0 {
                                    warn!("🔐 [LATTICE-TIP] block {} missing — skipping in proof chain", h);
                                }
                                last_extended_height = h;
                            }
                            Err(e) => {
                                warn!("🔐 [LATTICE-TIP] failed to load block {}: {}", h, e);
                                break; // retry next tick
                            }
                        }
                    }
                    {
                        let mut guard = proof_slot.write().await;
                        *guard = Some(current_proof.clone());
                    }
                    // v10.9.51 (closes plan task #74): persist to RocksDB
                    // every PERSIST_INTERVAL extends so restart skips the
                    // 18s warmup walk. Worst-case loss = last PERSIST_INTERVAL
                    // extends (~1 ms of producer work to redo).
                    if extends_since_persist >= PERSIST_INTERVAL {
                        match bincode::serialize(&current_proof) {
                            Ok(bytes) => {
                                if let Err(e) = storage.save_tip_proof_bytes(&bytes).await {
                                    warn!(
                                        "🔐 [LATTICE-TIP v10.9.51] persist failed at height {}: {} — will retry on next batch",
                                        last_extended_height, e
                                    );
                                } else {
                                    debug!(
                                        "🔐 [LATTICE-TIP v10.9.51] persisted proof at height {} ({} bytes, {} extends since last save)",
                                        last_extended_height, bytes.len(), extends_since_persist
                                    );
                                    extends_since_persist = 0;
                                }
                            }
                            Err(e) => {
                                warn!(
                                    "🔐 [LATTICE-TIP v10.9.51] bincode serialize failed at height {}: {} — skipping persist",
                                    last_extended_height, e
                                );
                            }
                        }
                    }
                    if last_extended_height % 10_000 == 0 && last_extended_height > 0 {
                        info!(
                            "🔐 [LATTICE-TIP] extended proof through height {} (anchor={}, transcript advance)",
                            last_extended_height, current_proof.anchor_height
                        );
                    }
                }
            });
        }

        // 🚀 v1.0.3-beta: CRITICAL FIX #2 - Add P2P peer height announcements
        // BUG: v1.0.2-beta NEVER sends height announcements, causing network_height=0 on all fresh nodes
        // FIX: Announce our height every 30 seconds so peers can discover network height via P2P
        // v1.0.2: Reduced from 5s to 30s to save bandwidth (height-change guard sends immediately on new blocks)
        // This is the PRIMARY sync discovery mechanism (HTTP bootstrap is fallback only)
        if let Some(command_tx) = &state.libp2p_command_tx {
            info!("🚀 [PEER HEIGHTS] Starting P2P height announcement task (every 30s)");
            let command_tx_clone = command_tx.clone();
            let storage_clone = state.storage_engine.clone();
            let network_id = std::env::var("Q_NETWORK_ID")
                .ok()
                .and_then(|s| s.parse::<q_types::NetworkId>().ok())
                .unwrap_or(q_types::NetworkId::MainnetGenesis); // ✅ v1.3.2-beta: Phase 16 default (Bug #6 fix)
            let local_peer_id = {
                let peer_info = state.libp2p_peer_info.read().await;
                peer_info.0.clone()
            };
            // v8.7.0: Capture admin wallet for distributed operator fee announcements
            let admin_wallet_clone = state.admin_wallet.clone();

            tokio::spawn(async move {
                let mut interval = tokio::time::interval(std::time::Duration::from_secs(30));
                interval.tick().await; // Skip first immediate tick
                let mut last_announced_height: u64 = 0;

                info!("📡 [PEER HEIGHTS] P2P announcement task started (Peer ID: {}...)",
                     if local_peer_id.len() >= 16 { &local_peer_id[..16] } else { &local_peer_id });

                loop {
                    interval.tick().await;

                    // Get our current highest block
                    let current_height = match storage_clone.get_latest_qblock().await {
                        Ok(Some(block)) => block.header.height,
                        Ok(None) => {
                            // No blocks yet, skip announcement
                            continue;
                        }
                        Err(e) => {
                            error!("📡 [PEER HEIGHTS] Failed to get latest block: {}", e);
                            continue;
                        }
                    };

                    // Only announce when height changes (avoid spamming network)
                    if current_height == last_announced_height {
                        continue;
                    }
                    last_announced_height = current_height;

                    // Create announcement using the same struct as receiver
                    #[derive(serde::Serialize, serde::Deserialize)]
                    struct PeerHeightAnnouncement {
                        peer_id: String,
                        highest_block: u64,
                        #[serde(default)]
                        tip_hash: Option<String>,
                        #[serde(default)]
                        operator_wallet: Option<String>,
                    }

                    // v5.2.0: Include tip block hash for fork detection
                    let tip_hash_str = match storage_clone.get_qblock_by_height(current_height).await {
                        Ok(Some(block)) => Some(hex::encode(block.calculate_hash())),
                        _ => None,
                    };

                    // v8.7.0: Include operator wallet for distributed fee splitting
                    let op_wallet = {
                        let w = admin_wallet_clone.clone();
                        const FOUNDER_WALLET_HEX: &str =
                            "efca1e8c1f46e91013b4073898c771bb3d566453537ccf87e834505925e50723";
                        if w.is_empty() || w == FOUNDER_WALLET_HEX {
                            None
                        } else {
                            Some(w)
                        }
                    };

                    let announcement = PeerHeightAnnouncement {
                        peer_id: local_peer_id.clone(),
                        highest_block: current_height,
                        tip_hash: tip_hash_str,
                        operator_wallet: op_wallet,
                    };

                    // Serialize with postcard + zstd compression (saves ~50% bandwidth)
                    let announcement_bytes = match postcard::to_allocvec(&announcement) {
                        Ok(raw_bytes) => {
                            match zstd::encode_all(raw_bytes.as_slice(), 3) {
                                Ok(compressed) => compressed,
                                Err(_) => raw_bytes, // Fallback to uncompressed
                            }
                        }
                        Err(e) => {
                            error!("📡 [PEER HEIGHTS] Serialization failed: {}", e);
                            continue;
                        }
                    };

                    // Construct topic using network ID
                    let topic = network_id.peer_heights_topic();

                    info!("📡 [PEER HEIGHTS] Announcing height {} to P2P network on topic: {}",
                          current_height, topic);

                    // Send via NetworkCommand::PublishPeerHeight
                    if let Err(e) = command_tx_clone.send(q_network::NetworkCommand::PublishPeerHeight {
                        topic,
                        announcement_bytes,
                        height: current_height,
                    }) {
                        error!("📡 [PEER HEIGHTS] Failed to send publish command: {}", e);
                    } else {
                        debug!("✅ [PEER HEIGHTS] Successfully queued announcement for height {}", current_height);
                    }
                }
            });

            info!("✅ [PEER HEIGHTS] P2P announcement task spawned - fresh nodes will discover network height");
        } else {
            warn!("⚠️  [PEER HEIGHTS] Cannot start announcement task - libp2p command channel not available");
        }

        // Spawn task to receive blocks and forward to consensus
        let consensus_clone = state.consensus.clone();
        let storage_clone = state.storage_engine.clone();
        let balance_engine_sync = balance_engine.clone();

        // 🚀 v1.0.2-beta: Capture fast sync state for routing
        let fast_sync_enabled = state.fast_sync_enabled;
        let fast_sync_tx_clone = state.fast_sync_tx.clone();

        // 🔧 v1.0.33-beta: Clone atomic height and challenge cache for libp2p sync updates
        let current_height_atomic_clone = state.current_height_atomic.clone();
        let current_challenge_clone = state.current_challenge.clone();

        // 💰 v1.0.60-beta: Clone wallet_balances for P2P balance sync
        // CRITICAL FIX: Blocks synced via TurboSync must process coinbase transactions
        // to update wallet balances. Without this, users running their own nodes see 0 balance
        // even after mining rewards are earned (balances only existed on bootstrap node).
        let wallet_balances_sync = state.wallet_balances.clone();

        // v8.9.1: Clone token_balances for in-memory refresh after batch-sync state replay
        let token_balances_sync = state.token_balances.clone();

        // 🚀 v3.4.12-beta: Clone network height for EXTREME_SKIP_BALANCES auto-detection
        let network_height_sync = state.highest_network_height.clone();

        // v7.1.2: Clone event broadcaster for SSE balance notifications during sync
        let event_broadcaster_sync = state.event_broadcaster.clone();

        // v7.4.0: Clone OAuth2 storage for consent transaction processing during sync
        let oauth2_storage_sync = state.oauth2_storage.clone();

        tokio::spawn(async move {
            info!("🔄 Starting block sync receiver task...");
            while let Some(blocks) = block_sync_rx.recv().await {
                // ========================================
                // 🔍 v1.0.87-beta: COMPREHENSIVE BLOCK VALIDATION DEBUGGING
                // Log block details for sync diagnosis
                // ========================================
                let block_heights: Vec<u64> = blocks.iter().map(|b| b.header.height).collect();
                let min_height = block_heights.iter().min().copied().unwrap_or(0);
                let max_height = block_heights.iter().max().copied().unwrap_or(0);

                info!(
                    "📦 [BLOCK-RECV] Received {} blocks via libp2p sync | heights: {}-{} | range: {}",
                    blocks.len(),
                    min_height,
                    max_height,
                    max_height.saturating_sub(min_height) + 1
                );

                // ========================================
                // 🔐 v1.3.9-beta + v10.0.0 BATCH VERIFICATION: Validate all transaction signatures
                // using rayon parallel batch verification for Ed25519 signatures.
                // Non-Ed25519 (Dilithium5, SQIsign, hybrids) verified individually.
                // Batch threshold: >=16 sigs for parallel, else sequential (per peer review TR-2026-004).
                // Performance: 5-10x speedup during sync (100 sigs in ~0.5ms on 48 cores)
                // ========================================
                let validation_start = std::time::Instant::now();
                let mut valid_blocks: Vec<q_types::QBlock> = Vec::with_capacity(blocks.len());
                let mut rejected_blocks = 0u64;
                let mut total_txs_verified = 0u64;

                // Phase 1: Collect Ed25519 signature data for batch verification
                struct Ed25519SigEntry {
                    block_idx: usize,
                    message: Vec<u8>,
                    signature: Vec<u8>,
                    public_key: Vec<u8>,
                }

                let mut ed25519_batch: Vec<Ed25519SigEntry> = Vec::new();
                let mut non_ed25519_failures: std::collections::HashSet<usize> = std::collections::HashSet::new();

                for (block_idx, block) in blocks.iter().enumerate() {
                    for tx in &block.transactions {
                        if tx.is_coinbase() { continue; }
                        total_txs_verified += 1;

                        match tx.signature_phase {
                            q_types::TxSignaturePhase::Phase0Ed25519 => {
                                if tx.signature.len() == 64 {
                                    let public_key_bytes: Vec<u8> = if tx.data.len() >= 32 {
                                        tx.data[..32].to_vec()
                                    } else {
                                        tx.from.to_vec()
                                    };
                                    ed25519_batch.push(Ed25519SigEntry {
                                        block_idx,
                                        message: tx.hash().to_vec(),
                                        signature: tx.signature.clone(),
                                        public_key: public_key_bytes,
                                    });
                                } else {
                                    warn!("🚫 [BLOCK-TX-REJECT] Block {} TX {} invalid Ed25519 sig length: {}",
                                        block.header.height, hex::encode(&tx.id[..8]), tx.signature.len());
                                    non_ed25519_failures.insert(block_idx);
                                }
                            }
                            _ => {
                                if let Err(sig_err) = tx.verify_signature() {
                                    warn!("🚫 [BLOCK-TX-REJECT] Block {} TX {} ({:?}) invalid signature: {}",
                                        block.header.height, hex::encode(&tx.id[..8]),
                                        tx.signature_phase, sig_err);
                                    non_ed25519_failures.insert(block_idx);
                                }
                            }
                        }
                    }
                }

                // Phase 2: Batch verify Ed25519 signatures (>=16 parallel, else sequential)
                let mut ed25519_failed_blocks: std::collections::HashSet<usize> = std::collections::HashSet::new();
                let ed25519_count = ed25519_batch.len();

                if ed25519_count >= 16 {
                    use rayon::prelude::*;
                    use ed25519_dalek::{Verifier, VerifyingKey, Signature as Ed25519Sig};
                    let results: Vec<(usize, bool)> = ed25519_batch.par_iter().map(|entry| {
                        let valid = (|| -> Option<bool> {
                            let pk: &[u8; 32] = entry.public_key.as_slice().try_into().ok()?;
                            let sig: &[u8; 64] = entry.signature.as_slice().try_into().ok()?;
                            let pubkey = VerifyingKey::from_bytes(pk).ok()?;
                            let signature = Ed25519Sig::from_bytes(sig);
                            Some(pubkey.verify(&entry.message, &signature).is_ok())
                        })().unwrap_or(false);
                        (entry.block_idx, valid)
                    }).collect();
                    for (block_idx, valid) in results {
                        if !valid { ed25519_failed_blocks.insert(block_idx); }
                    }
                } else {
                    use ed25519_dalek::{Verifier, VerifyingKey, Signature as Ed25519Sig};
                    for entry in &ed25519_batch {
                        let valid = (|| -> Option<bool> {
                            let pk: &[u8; 32] = entry.public_key.as_slice().try_into().ok()?;
                            let sig: &[u8; 64] = entry.signature.as_slice().try_into().ok()?;
                            let pubkey = VerifyingKey::from_bytes(pk).ok()?;
                            let signature = Ed25519Sig::from_bytes(sig);
                            Some(pubkey.verify(&entry.message, &signature).is_ok())
                        })().unwrap_or(false);
                        if !valid { ed25519_failed_blocks.insert(entry.block_idx); }
                    }
                }

                // Phase 3: Build valid_blocks from combined results
                let all_failed: std::collections::HashSet<usize> = non_ed25519_failures
                    .union(&ed25519_failed_blocks).copied().collect();
                for (idx, block) in blocks.iter().enumerate() {
                    if all_failed.contains(&idx) {
                        rejected_blocks += 1;
                        warn!("🚫 [BLOCK-REJECT] Block {} rejected: invalid transaction signatures",
                            block.header.height);
                    } else {
                        valid_blocks.push(block.clone());
                    }
                }

                let validation_time = validation_start.elapsed();
                if total_txs_verified > 0 || rejected_blocks > 0 {
                    info!(
                        "🔐 [BATCH-TX-VALIDATION] Verified {} TXs ({} Ed25519 batch{}) in {:.2}ms | {} blocks accepted, {} rejected",
                        total_txs_verified, ed25519_count,
                        if ed25519_count >= 16 { " parallel" } else { " sequential" },
                        validation_time.as_secs_f64() * 1000.0,
                        valid_blocks.len(), rejected_blocks
                    );
                }

                // Replace blocks with only validated ones
                let blocks = valid_blocks;

                if blocks.is_empty() && rejected_blocks > 0 {
                    warn!("⚠️ [SYNC] All {} received blocks were rejected due to invalid transactions", rejected_blocks);
                    continue;
                }

                // ========================================
                // v7.4.0: Process OAuth2 consent transactions from DAG
                // ========================================
                for block in &blocks {
                    for tx in &block.transactions {
                        match tx.tx_type {
                            q_types::TransactionType::OAuth2ConsentGrant => {
                                if let Ok(data_str) = std::str::from_utf8(&tx.data) {
                                    if let Ok(data) = serde_json::from_str::<serde_json::Value>(data_str) {
                                        if let Some(hash) = data.get("consent_hash").and_then(|v| v.as_str()) {
                                            oauth2_storage_sync.store_consent_hash(hash.to_string()).await;
                                            tracing::debug!("🔐 [OAUTH2] On-chain consent grant: {}...", &hash[..hash.len().min(16)]);
                                        }
                                    }
                                }
                            }
                            q_types::TransactionType::OAuth2ConsentRevoke => {
                                if let Ok(data_str) = std::str::from_utf8(&tx.data) {
                                    if let Ok(data) = serde_json::from_str::<serde_json::Value>(data_str) {
                                        if let Some(hash) = data.get("consent_hash").and_then(|v| v.as_str()) {
                                            oauth2_storage_sync.revoke_consent_by_hash(hash).await;
                                            tracing::debug!("🔐 [OAUTH2] On-chain consent revoke: {}...", &hash[..hash.len().min(16)]);
                                        }
                                    }
                                }
                            }
                            _ => {}
                        }
                    }
                }

                // ========================================
                // 🚀 v1.0.2-beta PHASE 1A: FAST SYNC ROUTING
                // Route blocks to SafeBatchedWriter for 150-250 BPS performance
                // ========================================
                if fast_sync_enabled {
                    if let Some(ref tx) = fast_sync_tx_clone {
                        let mut sent_count = 0;
                        let mut failed_count = 0;

                        for block in blocks.clone() {
                            match tx.send(block.clone()).await {
                                Ok(_) => {
                                    sent_count += 1;
                                }
                                Err(e) => {
                                    error!("❌ Fast sync channel error for block {}: {}, falling back to direct write",
                                           block.header.height, e);
                                    failed_count += 1;

                                    // Fallback to direct atomic write
                                    let tx = match storage_clone.begin_transaction().await {
                                        Ok(tx) => tx,
                                        Err(e) => {
                                            error!("❌ Failed to begin fallback transaction for block {}: {:?}",
                                                   block.header.height, e);
                                            continue;
                                        }
                                    };

                                    if let Err(e) = balance_engine_sync
                                        .process_block_mining_rewards_tx(&tx, &block)
                                        .await
                                    {
                                        error!("❌ Fallback balance processing failed for block {}: {:?}",
                                               block.header.height, e);
                                        continue;
                                    }

                                    if let Err(e) = tx.save_qblock(&block).await {
                                        error!(
                                            "❌ Fallback save failed for block {}: {:?}",
                                            block.header.height, e
                                        );
                                        continue;
                                    }

                                    match tx.commit().await {
                                        Ok(_) => {
                                            // v8.7.3: State replay for fast-sync fallback
                                            if let Some(rocks_db) = storage_clone.get_rocks_db_handle() {
                                                q_storage::replay_block_state_changes(&rocks_db, &block);
                                            }
                                        }
                                        Err(e) => {
                                            error!(
                                                "❌ Fallback commit failed for block {}: {:?}",
                                                block.header.height, e
                                            );
                                        }
                                    }
                                }
                            }
                        }

                        if sent_count > 0 {
                            info!(
                                "🚀 Fast sync: {} blocks sent to SafeBatchedWriter",
                                sent_count
                            );
                        }
                        if failed_count > 0 {
                            warn!(
                                "⚠️  {} blocks failed to send to fast sync, used fallback",
                                failed_count
                            );
                        }

                        // 💰 v8.3.0: Sync HashMap from RocksDB (authoritative source) for fast sync path.
                        // Previous incremental add caused balance drift — HashMap diverged from
                        // RocksDB truth, causing flickering between ~377 and ~220 QUG.
                        // Only update if RocksDB > current (SafeBatchedWriter may not have committed yet).
                        //
                        // v8.4.4: Split into two phases — RocksDB reads FIRST (no lock held),
                        // then write lock only for the in-memory HashMap update (microseconds).
                        // Previously held write lock during ALL RocksDB reads, blocking balance API calls.
                        {
                            // Phase 1: Read from RocksDB WITHOUT holding the write lock
                            let mut updates: Vec<([u8; 32], u128)> = Vec::new();
                            for block in &blocks {
                                for tx in &block.transactions {
                                    if tx.from == [0u8; 32] {
                                        let address_hex = hex::encode(&tx.to);
                                        if let Ok(actual_balance) = storage_clone.get_balance(&address_hex).await {
                                            updates.push((tx.to, actual_balance));
                                        }
                                    }
                                }
                            }

                            // Phase 2: Acquire write lock only for the HashMap update (microseconds)
                            if !updates.is_empty() {
                                let mut balances = wallet_balances_sync.write().await;
                                let mut synced_addresses = 0u64;
                                for (addr, actual_balance) in &updates {
                                    let current = balances.get(addr).copied().unwrap_or(0);
                                    if *actual_balance > current {
                                        balances.insert(*addr, *actual_balance);
                                        synced_addresses += 1;
                                    }
                                }
                                drop(balances);
                                if synced_addresses > 0 {
                                    info!(
                                        "💰 [FAST SYNC BALANCE v8.3.0] Synced {} addresses from RocksDB",
                                        synced_addresses
                                    );
                                }
                            }
                        }

                        // Skip the normal processing loop since we used fast sync
                        continue;
                    }
                }

                // ========================================
                // v1.0.42-beta: BATCHED TRANSACTIONS - Process blocks in batches for 10-50x faster sync
                // ========================================
                // OPTIMIZATION: Instead of per-block transactions (~30-50ms overhead each),
                // batch N blocks into a single transaction. This dramatically reduces commit overhead.
                //
                // Performance comparison:
                // - Old: 1000 blocks × 30ms/commit = 30 seconds
                // - New: 1000 blocks ÷ 50 batch = 20 commits × 50ms = 1 second
                //
                // Safety: Each batch is still atomic - if commit fails, entire batch rolls back.
                // Recovery: On batch failure, fall back to per-block commits for that batch.
                const BATCH_SIZE: usize = 50;  // Commit every 50 blocks (tunable)
                const LOG_INTERVAL: usize = 100;  // Log every 100 blocks to reduce I/O

                // v1.0.2: ALWAYS process full balance state (coinbase + transfers).
                // DO NOT reintroduce Q_EXTREME_SKIP_BALANCES or any analogous threshold here.
                // Coinbase-only sync silently drops transfer transactions, producing missing
                // wallets and inflated supply. The resulting state diverges from the network,
                // and at BAL-001 (block 20,000,000) such nodes produce wrong state_root and
                // are rejected. Wallet balances are consensus-critical — there is no valid
                // "fast but approximate" mode. See docs/technical-review-sync-architecture-2026-05-12.md.
                let mut balance_updates_total = 0;
                let mut blocks_committed = 0;
                let mut blocks_already_processed = 0;
                let mut blocks_failed = 0;
                let mut max_committed_height = 0u64;

                // Process blocks in batches
                for batch_chunk in blocks.chunks(BATCH_SIZE) {
                    // Begin transaction for this batch
                    let tx = match storage_clone.begin_transaction().await {
                        Ok(tx) => tx,
                        Err(e) => {
                            error!("❌ [BATCH-SYNC] Transaction start FAILED: {:?}", e);
                            blocks_failed += batch_chunk.len();
                            continue;
                        }
                    };

                    let batch_start_height = batch_chunk.first().map(|b| b.header.height).unwrap_or(0);
                    let batch_end_height = batch_chunk.last().map(|b| b.header.height).unwrap_or(0);

                    // Log batch start (reduced logging)
                    if batch_start_height % LOG_INTERVAL as u64 == 0 {
                        debug!("🔄 [BATCH-SYNC] Processing batch {} blocks ({}-{})",
                            batch_chunk.len(), batch_start_height, batch_end_height);
                    }

                    let mut batch_balance_updates = 0;
                    let mut batch_blocks_saved = 0;
                    let mut batch_already_processed = 0;

                    // v1.0.2 debug: tally coinbase vs transfer tx counts up-front so we
                    // can prove transfers are being processed (vs the old coinbase-only path).
                    // Mirrors turbo_sync.rs:4411 — both sync paths now have identical logging.
                    let (mut batch_coinbase_tx, mut batch_transfer_tx) = (0u64, 0u64);
                    for block in batch_chunk {
                        for tx_item in &block.transactions {
                            if tx_item.is_coinbase() {
                                batch_coinbase_tx += 1;
                            } else {
                                batch_transfer_tx += 1;
                            }
                        }
                    }
                    debug!(
                        "📊 [BATCH-SYNC] Tx breakdown: {} coinbase, {} transfer across {} blocks ({}-{})",
                        batch_coinbase_tx, batch_transfer_tx, batch_chunk.len(),
                        batch_start_height, batch_end_height
                    );

                    // Process all blocks in this batch within the same transaction.
                    // Always process coinbase + transfers — see invariant comment above.
                    for block in batch_chunk {
                        let updates = match balance_engine_sync
                            .process_block_mining_rewards_tx(&tx, block)
                            .await
                        {
                            Ok(updates) => updates,
                            Err(BalanceConsensusError::AlreadyProcessed(_hash)) => {
                                batch_already_processed += 1;
                                Vec::new()
                            }
                            Err(e) => {
                                // Log only first error in batch
                                if batch_blocks_saved == 0 {
                                    error!("❌ [BATCH-SYNC] Balance processing failed for block {}: {:?}",
                                        block.header.height, e);
                                }
                                continue;
                            }
                        };

                        // Save block to transaction (buffered, not committed yet)
                        if let Err(e) = tx.save_qblock(block).await {
                            error!("❌ [BATCH-SYNC] Block save failed for {}: {:?}",
                                block.header.height, e);
                            continue;
                        }

                        batch_balance_updates += updates.len();
                        batch_blocks_saved += 1;
                    }

                    // Commit entire batch atomically
                    match tx.commit().await {
                        Ok(_) => {
                            // 🔄 v8.7.3: Deterministic state replay for batch-synced blocks
                            if let Some(rocks_db) = storage_clone.get_rocks_db_handle() {
                                for block in batch_chunk {
                                    q_storage::replay_block_state_changes(&rocks_db, block);
                                }
                            }

                            balance_updates_total += batch_balance_updates;
                            blocks_committed += batch_blocks_saved;
                            blocks_already_processed += batch_already_processed;

                            // 🔧 v1.0.82-beta: CRITICAL FIX for batch sync loop bug
                            // BUG: Was updating height cache with batch_end_height, but Transaction
                            // only updates qblock:latest for TRULY contiguous blocks. This caused
                            // cache to race ahead while actual contiguous chain stayed behind.
                            // SYMPTOM: Same blocks 53947-53996 committed repeatedly in endless loop.
                            // FIX: Read actual qblock:latest from DB after commit, use that for cache.
                            let actual_pointer = storage_clone
                                .get_latest_qblock_height()
                                .await
                                .ok()
                                .flatten()
                                .unwrap_or(0);

                            if actual_pointer > max_committed_height {
                                max_committed_height = actual_pointer;
                                storage_clone.update_height_cache(actual_pointer).await;
                            }

                            // Log batch completion (reduced frequency)
                            if batch_end_height % LOG_INTERVAL as u64 == 0 || batch_end_height == blocks.last().map(|b| b.header.height).unwrap_or(0) {
                                info!(
                                    "✅ [BATCH-SYNC] Committed {} blocks ({}-{}), {} balance updates (coinbase={} transfer={})",
                                    batch_blocks_saved, batch_start_height, batch_end_height,
                                    batch_balance_updates, batch_coinbase_tx, batch_transfer_tx
                                );
                            }

                            // v1.0.2: Periodic wallet/supply snapshot — every 10k blocks during sync.
                            // Lets us watch the divergence story unfold in real time: if a fresh
                            // node ends up with fewer wallets / lower supply than Epsilon at the
                            // same height, something is silently dropping state updates.
                            if batch_end_height % 10_000 == 0 && batch_end_height > 0 {
                                if let Ok(balances) = storage_clone.load_wallet_balances().await {
                                    let wallet_count = balances.len();
                                    let total: u128 = balances.values().copied().sum();
                                    let total_qug = total / 1_000_000_000_000_000_000_000_000u128;
                                    info!(
                                        "📈 [BATCH-SYNC SNAPSHOT] h={} wallets={} supply={} QUG \
                                         (compare with another node at same height to detect divergence)",
                                        batch_end_height, wallet_count, total_qug
                                    );
                                    // Compute balance_root for cross-node comparison. This is the
                                    // SAME hash that ends up in block.header.state_root, so two
                                    // nodes with identical state will compute identical roots.
                                    match storage_clone.compute_balance_root_for_block().await {
                                        Ok(root) if root != [0u8; 32] => {
                                            info!(
                                                "🔐 [BATCH-SYNC SNAPSHOT] h={} balance_root={} (cross-node should match)",
                                                batch_end_height, hex::encode(&root[..8])
                                            );
                                        }
                                        Ok(_) => debug!("🔐 [BATCH-SYNC SNAPSHOT] h={} balance_root=zero (empty state)", batch_end_height),
                                        Err(e) => warn!("⚠️ [BATCH-SYNC SNAPSHOT] h={} balance_root compute failed: {}", batch_end_height, e),
                                    }
                                }
                            }
                        }
                        Err(e) => {
                            error!("❌ [BATCH-SYNC] Batch commit FAILED ({}-{}): {:?}",
                                batch_start_height, batch_end_height, e);
                            blocks_failed += batch_chunk.len();

                            // FALLBACK: On batch failure, retry blocks individually
                            warn!("🔄 [BATCH-SYNC] Falling back to per-block commits for failed batch");
                            for block in batch_chunk {
                                if let Ok(fallback_tx) = storage_clone.begin_transaction().await {
                                    let _ = balance_engine_sync
                                        .process_block_mining_rewards_tx(&fallback_tx, block)
                                        .await;
                                    if fallback_tx.save_qblock(block).await.is_ok() {
                                        if fallback_tx.commit().await.is_ok() {
                                            // v8.7.3: State replay for fallback path
                                            if let Some(rocks_db) = storage_clone.get_rocks_db_handle() {
                                                q_storage::replay_block_state_changes(&rocks_db, block);
                                            }
                                            blocks_committed += 1;
                                            blocks_failed -= 1;
                                        }
                                    }
                                }
                            }
                            // 🔧 v1.0.82-beta: Same fix as above - use actual pointer not block heights
                            let actual_pointer = storage_clone
                                .get_latest_qblock_height()
                                .await
                                .ok()
                                .flatten()
                                .unwrap_or(0);
                            if actual_pointer > max_committed_height {
                                max_committed_height = actual_pointer;
                                storage_clone.update_height_cache(actual_pointer).await;
                            }
                        }
                    }
                }

                // Batch summary for diagnostics (simplified for v1.0.42-beta)
                info!(
                    "📊 [BATCH-SYNC] Complete: received={}, committed={}, already_processed={}, failed={}, balance_updates={}",
                    blocks.len(),
                    blocks_committed,
                    blocks_already_processed,
                    blocks_failed,
                    balance_updates_total
                );
                if balance_updates_total > 0 {
                    info!(
                        "💰 [BATCH-SYNC] Processed {} balance updates for {}/{} blocks",
                        balance_updates_total,
                        blocks_committed,
                        blocks.len()
                    );
                }

                // ========================================
                // 💰 v1.1.23-beta CRITICAL FIX: REMOVED duplicate P2P balance sync code
                //
                // ROOT CAUSE: Same bug as v1.0.88-beta balance overwrite issue.
                // - balance_engine_sync.process_block_mining_rewards_tx() (line 2408-2425)
                //   already calls add_balance() which correctly ADDS to RocksDB.
                // - The code below was then calling set_balance() with HashMap-derived value,
                //   OVERWRITING the correct balance (especially after restart when HashMap is empty).
                //
                // FIX: Remove the duplicate code. process_block_mining_rewards_tx() handles everything.
                // Just sync the HashMap from RocksDB for fast in-memory lookups.
                // ========================================
                {
                    // Sync HashMap from RocksDB (source of truth) for fast lookups
                    // v7.1.2: Also emit SSE events so frontend sees balance updates during sync
                    //
                    // v8.4.4: Split into two phases — RocksDB reads FIRST (no lock held),
                    // then write lock only for the HashMap update (microseconds).
                    // Previously held write lock during ALL RocksDB reads, blocking balance API calls.
                    let mut synced_addresses = 0u64;
                    let mut sse_updates: Vec<(String, u128, u128)> = Vec::new(); // (addr, old, new)

                    // Phase 1: Read from RocksDB WITHOUT holding the write lock
                    // v1.0.2: Include ALL affected addresses (coinbase + transfers), not just coinbase.
                    // Previously only coinbase recipients were synced, so transfer-only wallets
                    // were never loaded into the HashMap after fast-sync.
                    let mut db_reads: Vec<([u8; 32], String, u128)> = Vec::new();
                    let mut seen_addresses: std::collections::HashSet<[u8; 32]> = std::collections::HashSet::new();
                    for block in &blocks {
                        for tx in &block.transactions {
                            // Always include recipient
                            if !seen_addresses.contains(&tx.to) {
                                seen_addresses.insert(tx.to);
                                let address_hex = hex::encode(&tx.to);
                                if let Ok(actual_balance) = storage_clone.get_balance(&address_hex).await {
                                    db_reads.push((tx.to, address_hex, actual_balance));
                                }
                            }
                            // Include sender if non-coinbase
                            if tx.from != [0u8; 32] && !seen_addresses.contains(&tx.from) {
                                seen_addresses.insert(tx.from);
                                let address_hex = hex::encode(&tx.from);
                                if let Ok(actual_balance) = storage_clone.get_balance(&address_hex).await {
                                    db_reads.push((tx.from, address_hex, actual_balance));
                                }
                            }
                        }
                    }

                    // Phase 2: Acquire write lock only for HashMap update (microseconds)
                    if !db_reads.is_empty() {
                        let mut balances = wallet_balances_sync.write().await;
                        for (addr_bytes, address_hex, actual_balance) in &db_reads {
                            let old_balance = balances.get(addr_bytes).copied().unwrap_or(0);
                            if *actual_balance != old_balance {
                                sse_updates.push((address_hex.clone(), old_balance, *actual_balance));
                            }
                            balances.insert(*addr_bytes, *actual_balance);
                            synced_addresses += 1;
                        }
                        drop(balances);
                    }

                    // v7.1.2: Emit SSE BalanceUpdated events for miners whose balances changed
                    if !sse_updates.is_empty() {
                        // Deduplicate - keep only latest balance per address
                        let mut latest_by_addr: std::collections::HashMap<String, (u128, u128)> = std::collections::HashMap::new();
                        for (addr, old, new_bal) in &sse_updates {
                            latest_by_addr.insert(addr.clone(), (*old, *new_bal));
                        }

                        for (addr, (old_bal, new_bal)) in &latest_by_addr {
                            let wallet_with_prefix = if addr.starts_with("qnk") {
                                addr.clone()
                            } else {
                                format!("qnk{}", addr)
                            };
                            let _ = event_broadcaster_sync.broadcast(
                                q_api_server::streaming::StreamEvent::BalanceUpdated {
                                    wallet_address: wallet_with_prefix,
                                    old_balance: *old_bal as f64 / QUG_DISPLAY_DIVISOR,
                                    new_balance: *new_bal as f64 / QUG_DISPLAY_DIVISOR,
                                    change_reason: "mining_reward".to_string(),
                                    timestamp: chrono::Utc::now(),
                                    block_hash: None,
                                    block_height: blocks.last().map(|b| b.header.height),
                                    confirmation_status: "confirmed".to_string(),
                                    from_address: None,
                                    tx_hash: None,
                                    memo: None,
                                }
                            ).await;
                        }
                        debug!("📡 [SYNC→SSE v7.1.2] Emitted {} balance updates via SSE", latest_by_addr.len());
                    }

                    if synced_addresses > 0 {
                        debug!(
                            "💰 [P2P CACHE SYNC] {} addresses synced from RocksDB to HashMap",
                            synced_addresses
                        );
                    }
                }

                // v8.9.1: Refresh in-memory token_balances after batch-sync state replay.
                // StateApplicator writes to CF_TOKEN_BALANCES but in-memory HashMap is
                // loaded from CF_MANIFEST. Use load_token_balances() which merges both.
                // Only do this when blocks were actually committed (avoid no-op overhead).
                if blocks_committed > 0 {
                    match storage_clone.load_token_balances().await {
                        Ok(persisted) if !persisted.is_empty() => {
                            let count = persisted.len();
                            let mut tb = token_balances_sync.write().await;
                            let mut updated = 0usize;
                            for (key, amount) in &persisted {
                                let current = tb.get(key).copied().unwrap_or(0);
                                if *amount != current {
                                    tb.insert(*key, *amount);
                                    updated += 1;
                                }
                            }
                            drop(tb);
                            if updated > 0 {
                                info!("🪙 [BATCH-SYNC v8.9.1] Refreshed {}/{} token balances from RocksDB", updated, count);
                            }
                        }
                        Ok(_) => {}
                        Err(e) => {
                            warn!("⚠️ [BATCH-SYNC v8.9.1] Failed to reload token balances: {}", e);
                        }
                    }
                }

                // v10.8.4: Only advance current_height_atomic for sequential batches.
                // During turbo sync, parallel streams deliver blocks far ahead of the
                // contiguous chain tip, causing the atomic to jump millions of blocks at once.
                // This makes the node falsely advertise height 13.9M when contiguous is 105K,
                // causing peers to request blocks this node can't serve.
                // Guard: only update if the batch is within 5000 blocks of the current atomic.
                // The periodic height-reconcile task (fetch_max from DB) handles wider advances.
                if !blocks.is_empty() {
                    let max_height = blocks.iter().map(|b| b.header.height).max().unwrap_or(0);
                    let current_atomic = current_height_atomic_clone.load(std::sync::atomic::Ordering::Acquire);
                    if max_height > current_atomic && max_height <= current_atomic + 5_000 {
                        current_height_atomic_clone.store(
                            max_height,
                            std::sync::atomic::Ordering::Release
                        );
                        info!("📈 [LIBP2P SYNC] Updated current_height_atomic: {} → {}", current_atomic, max_height);
                        *current_challenge_clone.write().await = None;
                    }
                }

                // Forward to consensus for validation
                let mut consensus = consensus_clone.write().await;
                for block in blocks {
                    // Convert block to DAG vertex for consensus processing
                    // For now, just log - full consensus integration requires vertex conversion
                    info!(
                        "🎯 Block {} ready for consensus validation",
                        block.header.height
                    );
                }
            }
            info!("⚠️  Block sync receiver task terminated");
        });

        // Phase 3c: Spawn TurboSync task - v1.0.45-beta HIGH PERFORMANCE SYNC
        // Optimizations implemented:
        // 1. 5-second intervals (6x more sync cycles than 30s)
        // 2. 2000 block batch size in check_and_sync_blocks (2x larger)
        // 3. Stall detection ensures requests don't pile up (v1.0.43-beta)
        // 4. Metrics tracking for blocks/second throughput
        // 5. v1.0.45-beta: Beautiful progress bar with ETA
        //
        // Theoretical max: 2000 blocks / 5 seconds = 400 blocks/sec
        // Actual limited by: network latency, disk I/O, peer response time
        let manager_clone_for_sync = libp2p_manager.clone();
        let storage_clone_for_sync = state.storage_engine.clone();
        // v2.2.1-beta: Clone highest_network_height for progress display fix
        let highest_network_height_for_sync = state.highest_network_height.clone();
        tokio::spawn(async move {
            // v1.0.45-beta: Beautiful progress bar helper
            fn make_progress_bar(current: u64, target: u64, width: usize) -> String {
                if target == 0 || current >= target {
                    return format!("[{}] 100%", "█".repeat(width));
                }
                let progress = (current as f64 / target as f64).min(1.0);
                let filled = (progress * width as f64) as usize;
                let empty = width - filled;
                let percent = (progress * 100.0) as u8;
                format!("[{}{}] {}%", "█".repeat(filled), "░".repeat(empty), percent)
            }

            // v1.0.45-beta: Format duration nicely
            fn format_eta(seconds: u64) -> String {
                if seconds < 60 {
                    format!("{}s", seconds)
                } else if seconds < 3600 {
                    format!("{}m {}s", seconds / 60, seconds % 60)
                } else {
                    format!("{}h {}m", seconds / 3600, (seconds % 3600) / 60)
                }
            }

            info!("╔════════════════════════════════════════════════════════════╗");
            info!("║       🚀 TurboSync v1.0.46-beta - Extreme Speed Edition    ║");
            info!("║           2s intervals | 5k batches | Progress Bar         ║");
            info!("╚════════════════════════════════════════════════════════════╝");

            // TurboSync configuration
            // v1.0.46-beta: Reduced to 2s for even faster sync polling
            const SYNC_INTERVAL_SECS: u64 = 2;  // Was 5s in v1.0.44, 30s originally
            const PROGRESS_BAR_WIDTH: usize = 30;

            let mut interval = tokio::time::interval(tokio::time::Duration::from_secs(SYNC_INTERVAL_SECS));
            let mut last_height: u64 = 0;
            let start_time = std::time::Instant::now();
            let mut last_display_time = std::time::Instant::now();

            loop {
                interval.tick().await;

                // Get current local height for metrics
                let current_height = match storage_clone_for_sync.get_highest_contiguous_block().await {
                    Ok(h) => h,
                    Err(e) => {
                        error!("❌ TurboSync: Failed to get local height: {}", e);
                        continue;
                    }
                };

                // Get network height from BOTH sources and use the highest
                // v2.2.1-beta: CRITICAL FIX - manager.known_network_height wasn't being updated
                // from gossipsub peer announcements, only from block-pack responses!
                // This caused the progress bar to show "Synced! 10000/10000" when actual network was 791929
                let network_height = {
                    // Source 1: Manager's known height (updated from block-pack responses)
                    let manager_height = {
                        let manager = manager_clone_for_sync.lock().await;
                        manager.get_known_network_height()
                    };

                    // Source 2: App state's highest height (updated from gossipsub peer announcements)
                    let gossip_height = highest_network_height_for_sync
                        .load(std::sync::atomic::Ordering::SeqCst);

                    // Use the higher of the two (at least one should be accurate)
                    let best_height = manager_height.max(gossip_height);

                    // v2.2.1-beta: DEBUG - Log when sources disagree significantly
                    if manager_height > 0 && gossip_height > 0 && (manager_height as i64 - gossip_height as i64).abs() > 100 {
                        debug!("📊 [HEIGHT MISMATCH] manager={}, gossip={}, using={}",
                              manager_height, gossip_height, best_height);
                    }

                    best_height
                };

                // Calculate sync speed
                let height_gain = current_height.saturating_sub(last_height);
                let instant_bps = height_gain as f64 / SYNC_INTERVAL_SECS as f64;

                // Calculate overall average
                let total_elapsed = start_time.elapsed().as_secs_f64();
                let avg_bps = if total_elapsed > 0.0 && current_height > 0 {
                    current_height as f64 / total_elapsed
                } else {
                    0.0
                };

                // Calculate ETA
                let blocks_remaining = network_height.saturating_sub(current_height);
                let eta_secs = if avg_bps > 0.0 {
                    (blocks_remaining as f64 / avg_bps) as u64
                } else {
                    0
                };

                last_height = current_height;

                // Only show detailed log every 5 seconds to reduce spam
                let now = std::time::Instant::now();
                if now.duration_since(last_display_time).as_secs() >= 5 {
                    last_display_time = now;

                    // Determine sync status
                    let (status_icon, status_text) = if network_height == 0 {
                        ("🔍", "Discovering network...")
                    } else if current_height >= network_height {
                        ("✅", "Synced!")
                    } else if height_gain > 0 {
                        ("🚀", "Syncing")
                    } else {
                        ("⏳", "Waiting for blocks...")
                    };

                    // Create progress bar
                    let progress_bar = make_progress_bar(current_height, network_height, PROGRESS_BAR_WIDTH);

                    // Format numbers with thousands separators
                    let current_fmt = format!("{}", current_height);
                    let network_fmt = if network_height > 0 { format!("{}", network_height) } else { "?".to_string() };

                    // v1.0.45-beta: Beautiful single-line sync status
                    info!("┃ {} {} {} | {}/{} | {:.0} b/s | ETA: {}",
                          status_icon, status_text, progress_bar, current_fmt, network_fmt, avg_bps,
                          if eta_secs > 0 { format_eta(eta_secs) } else { "—".to_string() });

                    // Show speed indicator on separate line when actively syncing
                    if height_gain > 0 && network_height > 0 {
                        info!("┃ +{} blocks this cycle | instant: {:.0} b/s", height_gain, instant_bps);
                    }
                }

                // v1.3.11-beta: DISABLED - check_and_sync_blocks uses request_blocks_from_peer
                // which stores requests in outstanding_sync_requests, but the response handler
                // looks in pending_block_requests - causing request_id mismatch and sync failures.
                //
                // TurboSync (sync_to_height) is the correct sync mechanism - it uses
                // request_blocks_batch_async which properly registers in pending_block_requests.
                // TurboSync is triggered from the main sync loop at line ~9318.
                //
                // Keeping this code path disabled prevents competing sync systems.
                let _ = &manager_clone_for_sync; // Keep variable alive but unused
            }
        });

        info!("✅ Phase 3 block synchronization fully integrated!");
    } else {
        warn!("⚠️  libp2p manager not available - Phase 3 block sync disabled");
    }

    // ========================================
    // AI INFERENCE ENGINE INITIALIZATION
    // Privacy-first distributed inference with KV-cache optimization
    // v0.1.9-beta: ENABLED BY DEFAULT - Part of core node functionality
    // Users can disable with Q_DISABLE_AI=1 to save RAM
    // ========================================

    // Check if AI inference is explicitly disabled
    let ai_disabled = std::env::var("Q_DISABLE_AI")
        .map(|v| v == "1" || v.to_lowercase() == "true")
        .unwrap_or(false);

    if ai_disabled {
        info!("ℹ️  AI Inference Engine DISABLED (saves ~4GB RAM)");
        info!("   AI was manually disabled via Q_DISABLE_AI=1");
        info!("   To enable: unset Q_DISABLE_AI or set Q_DISABLE_AI=0");
        info!("   AI features like chat will return 503 Service Unavailable");
        state.inference_engine = None;
    } else {
        info!("🤖 AI Inference Engine ENABLED BY DEFAULT");
        info!("   Distributed AI ready for horizontal scaling across network nodes");
        info!("   To disable: export Q_DISABLE_AI=1 before starting node");
        info!("🤖 Initializing AI Inference Engine with KV-cache...");
        info!("   WARNING: This will consume ~30GB of RAM");

        // Auto-download model helper function
        async fn ensure_model_available() -> anyhow::Result<std::path::PathBuf> {
            use futures_util::StreamExt;
            use tokio::io::AsyncWriteExt;

            let model_dir = std::path::PathBuf::from("./models");
            tokio::fs::create_dir_all(&model_dir).await?;

            // v2.5.1-beta: Support BitNet b1.58 2B4T or fallback to Mistral-7B
            let model_name = std::env::var("Q_AI_MODEL").unwrap_or_else(|_| "bitnet".to_string());
            let model_path = if model_name.to_lowercase().contains("bitnet") {
                model_dir.join("bitnet-b1.58-2B-4T.gguf")
            } else {
                model_dir.join("Mistral-7B-Instruct-v0.3.Q4_K_M.gguf")
            };
            let tokenizer_config_path = model_dir.join("tokenizer_config.json");
            let tokenizer_json_path = model_dir.join("tokenizer.json");

            // Download tokenizer_config.json if it doesn't exist
            if !tokenizer_config_path.exists() {
                info!("📥 Downloading tokenizer_config.json from bootstrap node...");
                info!("   Source: https://quillon.xyz/downloads/tokenizer_config.json");

                let url = "https://quillon.xyz/downloads/tokenizer_config.json";
                let response = reqwest::get(url).await?;

                if !response.status().is_success() {
                    return Err(anyhow::anyhow!(
                        "Failed to download tokenizer config: HTTP {}",
                        response.status()
                    ));
                }

                let bytes = response.bytes().await?;
                tokio::fs::write(&tokenizer_config_path, bytes).await?;
                info!(
                    "✅ Tokenizer config downloaded: {:?}",
                    tokenizer_config_path
                );
            } else {
                info!(
                    "✅ Tokenizer config already exists locally at: {:?}",
                    tokenizer_config_path
                );
            }

            // Download tokenizer.json if it doesn't exist
            if !tokenizer_json_path.exists() {
                info!("📥 Downloading tokenizer.json from bootstrap node...");
                info!("   Source: https://quillon.xyz/downloads/tokenizer.json");

                let url = "https://quillon.xyz/downloads/tokenizer.json";
                let response = reqwest::get(url).await?;

                if !response.status().is_success() {
                    return Err(anyhow::anyhow!(
                        "Failed to download tokenizer.json: HTTP {}",
                        response.status()
                    ));
                }

                let bytes = response.bytes().await?;
                tokio::fs::write(&tokenizer_json_path, bytes).await?;
                info!("✅ Tokenizer.json downloaded: {:?}", tokenizer_json_path);
            } else {
                info!(
                    "✅ Tokenizer.json already exists locally at: {:?}",
                    tokenizer_json_path
                );
            }

            // If model doesn't exist, download from bootstrap node
            if !model_path.exists() {
                info!("📥 Downloading Mistral-7B model (4.1GB) from bootstrap node...");
                info!("   This is a one-time download and will be cached locally");
                info!(
                    "   Source: https://quillon.xyz/downloads/Mistral-7B-Instruct-v0.3.Q4_K_M.gguf"
                );

                let url = "https://quillon.xyz/downloads/Mistral-7B-Instruct-v0.3.Q4_K_M.gguf";
                let response = reqwest::get(url).await?;

                if !response.status().is_success() {
                    return Err(anyhow::anyhow!(
                        "Failed to download model: HTTP {}",
                        response.status()
                    ));
                }

                let total_size = response.content_length().unwrap_or(0);
                info!(
                    "   Download size: {:.2} GB",
                    total_size as f64 / 1_000_000_000.0
                );

                let mut file = tokio::fs::File::create(&model_path).await?;
                let mut downloaded: u64 = 0;
                let mut stream = response.bytes_stream();

                let progress_interval = 100 * 1024 * 1024; // Log every 100MB
                let mut last_logged = 0u64;

                while let Some(chunk) = stream.next().await {
                    let chunk = chunk?;
                    file.write_all(&chunk).await?;
                    downloaded += chunk.len() as u64;

                    // Log progress every 100MB
                    if downloaded - last_logged >= progress_interval {
                        let percent = if total_size > 0 {
                            (downloaded as f64 / total_size as f64 * 100.0)
                        } else {
                            0.0
                        };
                        info!(
                            "   Downloaded: {:.2} MB / {:.2} MB ({:.1}%)",
                            downloaded as f64 / 1_000_000.0,
                            total_size as f64 / 1_000_000.0,
                            percent
                        );
                        last_logged = downloaded;
                    }
                }

                file.flush().await?;
                info!(
                    "✅ Model downloaded successfully and cached at: {:?}",
                    model_path
                );
                info!(
                    "   File size: {:.2} GB",
                    downloaded as f64 / 1_000_000_000.0
                );
            } else {
                info!("✅ Model already exists locally at: {:?}", model_path);
            }

            Ok(model_path)
        }

        // 🚀 v1.0.17-beta: ON-DEMAND AI LOADING FIX
        // Don't load AI model at startup to avoid blocking HTTP server
        // AI will be loaded on-demand when chat API is first called
        info!("🚀 Configuring on-demand AI loading...");
        info!("   HTTP server will start immediately");
        info!("   AI model will load automatically when chat API is first used");
        info!("   This ensures HTTP API is available within <1 second of startup");

        state.mistralrs_engine = None; // Load on first chat API call
        state.inference_engine = None;
    } // end if ai_enabled

    // ========================================
    // PHASE 1: HIGH-PERFORMANCE CONSENSUS INITIALIZATION
    // Target: 50K+ TPS (baseline without SIMD/kernel optimizations)
    // ========================================
    info!("🚀 Initializing High-Performance Consensus System");
    info!("   Target: 50,000+ TPS (Phase 1)");
    info!("   Future: 200,000+ TPS (Phase 2 - Parallel Workers)");
    info!("   Future: 500,000+ TPS (Phase 3 - SIMD Crypto)");
    info!("   Future: 1,000,000+ TPS (Phase 4 - io_uring Kernel I/O)");

    // Determine number of parallel workers (4x CPU cores for I/O bound workload)
    let cpu_cores = num_cpus::get();
    let num_workers = (cpu_cores * 4).max(64); // Minimum 64 workers, optimal for 1M TPS target
    info!(
        "   Parallel Workers: {} ({}x CPU cores)",
        num_workers,
        num_workers / cpu_cores
    );

    // Initialize Production Mempool for high-throughput transaction batching
    let mempool_config = q_narwhal_core::production_mempool::MempoolConfig {
        max_transactions: 1_000_000,                  // 1M transaction capacity
        max_age: std::time::Duration::from_secs(300), // 5 minutes
        min_fee_per_byte: 1,                          // Low fees for high throughput
        max_transaction_size: 1024 * 1024,            // 1MB max tx size
        max_tx_per_validator_per_second: 100_000,     // 100K TPS per validator
        enable_byzantine_protection: true,
    };

    info!("📦 Initializing Production Mempool...");

    // Initialize ProductionTorClient for Bracha's reliable broadcast
    use q_narwhal_core::{ProductionTorClient, TorClientConfig};
    use q_types::Phase;

    let tor_config = TorClientConfig {
        socks_proxy: "127.0.0.1:9050".to_string(), // Default Tor SOCKS5 proxy
        connection_timeout: std::time::Duration::from_secs(30),
        max_pool_size: 100,
        enable_connection_pooling: true,
        connection_keep_alive: std::time::Duration::from_secs(300),
    };

    let production_tor_client: Option<Arc<dyn q_narwhal_core::TorClient>> = {
        let client = ProductionTorClient::new(tor_config);
        info!("✅ ProductionTorClient initialized successfully");
        info!("   Note: Tor connection will be attempted when broadcasting");
        let arc_client: Arc<dyn q_narwhal_core::TorClient> = Arc::new(client);
        Some(arc_client)
    };

    // Initialize ProductionMempool with Bracha's reliable broadcast
    let production_mempool: Option<Arc<q_narwhal_core::production_mempool::ProductionMempool>> =
        if let Some(tor_client) = production_tor_client {
            match q_narwhal_core::production_mempool::ProductionMempool::new(
                mempool_config,
                tor_client,
                Phase::Phase1, // Phase 1: Post-quantum cryptography
            )
            .await
            {
                Ok(mempool) => {
                    info!("✅ Production Mempool initialized with Tor broadcast");
                    info!("   Max transactions: 1M");
                    info!("   Byzantine protection: ENABLED");
                    info!("   Reliable broadcast: Bracha's protocol over Tor");
                    Some(Arc::new(mempool))
                }
                Err(e) => {
                    warn!("⚠️  Production Mempool initialization failed: {}", e);
                    info!("   Using fallback transaction pool");
                    None
                }
            }
        } else {
            info!("⚠️  Production Mempool skipped (Tor client unavailable)");
            info!("   Using fallback transaction pool for testing");
            None
        };

    // Initialize DAG-Knight Consensus with parallel processing
    info!("⚔️  Initializing DAG-Knight Consensus...");
    info!("   Workers: {} parallel vertex processors", num_workers);

    let dag_knight = match q_dag_knight::DAGKnightConsensus::new(
        node_id, 3, // f = 3 for 3f+1 = 10 total validators (minimum Byzantine fault tolerance)
    )
    .await
    {
        Ok(consensus) => {
            info!("✅ DAG-Knight Consensus initialized successfully");
            info!("   Validator ID: {}", hex::encode(node_id));
            info!("   Byzantine threshold: f=3 (tolerates 3 Byzantine nodes)");
            info!("   Quantum anchor election: VDF-based");
            info!("   Zero-message complexity ordering");
            Some(Arc::new(consensus))
        }
        Err(e) => {
            warn!("⚠️  DAG-Knight initialization failed: {}", e);
            info!("   Consensus ordering will be disabled");
            None
        }
    };

    // Update state with initialized consensus components
    state.production_mempool = production_mempool;
    state.dag_knight = dag_knight.clone();

    // ⚔️  v1.0.3-beta: Wire DAG-Knight consensus into block producer pool for dag_parents population
    if let Some(ref dag_knight_ref) = dag_knight {
        info!("⚔️  Wiring DAG-Knight consensus into block producer pool...");
        state
            .block_producer_pool
            .set_dag_knight(dag_knight_ref.clone());
        info!("✅ DAG parents population ACTIVATED for all producers!");
        info!("   Phase 1: Foundation for DAG-aware sync");
        info!("   Phase 2: 10-50x sync performance improvement (future)");

        // 🚀 v1.0.73-beta: CRITICAL FIX - Initialize committed round from blockchain height
        // Without this, tail fork protection blocks all new blocks after restart!
        let blockchain_height = state.current_height_atomic.load(std::sync::atomic::Ordering::Acquire);
        dag_knight_ref.initialize_committed_round(blockchain_height).await;
        info!(
            "🔧 [CONSENSUS SYNC] Committed round initialized to {} from blockchain",
            blockchain_height
        );
    } else {
        info!("ℹ️  No DAG-Knight consensus - dag_parents will be empty");
    }

    // 📦 v3.5.14-beta: Wire production mempool into block producer pool for P2P transaction inclusion
    // This is CRITICAL for P2P transaction propagation to work!
    // Without this, transactions received via gossipsub are queued but never included in blocks.
    if let Some(ref mempool_ref) = state.production_mempool {
        info!("📦 Wiring production mempool into block producer pool...");
        state
            .block_producer_pool
            .set_production_mempool(mempool_ref.clone());
        info!("✅ Production mempool ACTIVATED for all producers!");
        info!("   P2P transactions will be included in blocks");
        info!("   Fee-ordered transaction selection enabled");
    } else {
        warn!("⚠️  No production mempool - P2P transactions will NOT be included in blocks!");
        info!("   Transactions will only work via direct API submission");
    }

    // 📦 v3.5.20-beta: Wire tx_status into block producer pool for P2P transaction confirmations
    // This is CRITICAL for P2P transactions to be marked as Confirmed after block inclusion!
    // Without this, P2P transactions stay in "in_mempool" status forever.
    info!("📦 Wiring tx_status into block producer pool...");
    state
        .block_producer_pool
        .set_tx_status(state.tx_status.clone());
    info!("✅ Transaction status tracker ACTIVATED for all producers!");
    info!("   P2P transactions will be marked Confirmed after block inclusion");

    // ========================================
    // v2.4.6-beta: NARWHAL-CORE BFT CONSENSUS INITIALIZATION
    // Multi-validator Byzantine Fault Tolerant consensus with SQIsign signatures
    // ========================================
    info!("🔐 Initializing NarwhalCore BFT Consensus...");

    // Byzantine threshold f=1: tolerates 1 Byzantine validator, needs 2f+1=3 signatures for certificates
    let narwhal_core = q_narwhal_core::NarwhalCore::new_with_byzantine_threshold(
        node_id,
        Phase::Phase1, // Post-quantum phase with SQIsign signatures
        1,             // f=1 (3f+1=4 validators for full BFT, 2f+1=3 for quorum)
    );

    info!("✅ NarwhalCore BFT initialized successfully");
    info!("   Node ID: {}", hex::encode(&node_id[..8]));
    info!("   Byzantine threshold: f=1 (tolerates 1 Byzantine validator)");
    info!("   Certificate quorum: 2f+1 = 3 signatures required");
    info!("   Post-quantum: SQIsign Level I (204-byte signatures)");

    // Create validator announcement for P2P broadcast
    let validator_announcement = narwhal_core.create_validator_announcement();
    if validator_announcement.is_some() {
        info!("✅ Validator announcement created - will broadcast on P2P startup");
    } else {
        warn!("⚠️  No SQIsign keypair - validator announcement disabled");
    }

    // Store NarwhalCore in state
    let narwhal_core_arc = Arc::new(narwhal_core);
    state.narwhal_core = Some(narwhal_core_arc.clone());

    info!("✅ NarwhalCore stored in ServerState - BFT consensus ENABLED");

    // ========================================
    // QUILLON RESONANCE CONSENSUS - K-PARAMETER PHASE ANALYSIS
    // ========================================
    #[cfg(feature = "resonance")]
    {
        info!("🌊 Initializing Quillon Resonance Consensus with K-Parameter analysis...");

        let k_analyzer = q_resonance::KParameterAnalyzer::new()
            .with_planck_constant(1.0)
            .with_threshold(1.0);

        info!("✅ K-Parameter analyzer initialized");
        info!("   Formula: K = 2π √(ΔH · Δs · ℏ) / τ");
        info!("   Phase detection: Stable → Approaching → Critical");
        info!("   Dynamic parameter tuning: ACTIVE");

        state.k_parameter_analyzer = Some(Arc::new(k_analyzer));

        // ========================================
        // SHADOW MODE: DAG-Knight (Primary) + Q-Resonance (Shadow)
        // ========================================
        // Initialize Shadow Mode Coordinator if DAG-Knight is active
        if let Some(ref dag_knight_ref) = dag_knight {
            info!("🎭 Initializing Shadow Mode Coordinator...");

            // Create ResonanceCoordinator for shadow mode
            let resonance = q_resonance::ResonanceCoordinator::new(node_id.to_vec());
            let resonance_arc = Arc::new(resonance);

            // Configure shadow mode - v3.4.8-beta: HYBRID MODE ENABLED
            // Resonance complements DAG-Knight with physics-based consensus validation
            let shadow_config = q_resonance::ShadowModeConfig {
                enabled: true,
                agreement_threshold: 0.85, // 85% agreement required for migration
                observation_rounds: 100,   // Observe 100 rounds before auto-adjust
                hybrid_mode: true,         // 🎭 HYBRID MODE: Resonance complements DAG-Knight
                resonance_weight: 0.1,     // Start at 10% resonance influence (cautious)
                auto_adjust_weight: true,  // Auto-adjust based on agreement rate
                log_interval_rounds: 10,   // Log detailed metrics every 10 rounds
            };

            // Create ShadowModeCoordinator
            match q_resonance::ShadowModeCoordinator::new(
                dag_knight_ref.clone(),
                resonance_arc.clone(),
                shadow_config,
            )
            .await
            {
                Ok(shadow_coordinator) => {
                    info!("✅ Hybrid Mode Coordinator initialized - v3.4.8-beta");
                    info!("   🎯 Primary: DAG-Knight Consensus (90% weight)");
                    info!("   🌊 Complement: Quillon Resonance Consensus (10% weight)");
                    info!("   📊 Agreement Threshold: 85.0%");
                    info!("   🔄 Observation Rounds: 100");
                    info!("   ⚖️  Auto-weight adjustment: ENABLED");
                    info!("   🎭 MODE: HYBRID - Resonance complements DAG-Knight");
                    info!("   🎻 String-theoretic consensus: ACTIVE");
                    info!("   ⚡ Energy minimization: ENABLED");
                    info!("   🛡️  Spectral BFT Byzantine detection: ENABLED");

                    // Store both coordinators in app state
                    state.resonance_coordinator = Some(resonance_arc);
                    state.shadow_coordinator =
                        Some(Arc::new(tokio::sync::Mutex::new(shadow_coordinator)));
                }
                Err(e) => {
                    warn!("⚠️  Shadow Mode Coordinator initialization failed: {}", e);
                    warn!("   Continuing with ResonanceCoordinator only (no shadow mode)");
                    // Still store resonance coordinator without shadow mode
                    state.resonance_coordinator = Some(resonance_arc);
                }
            };
        }
    }
    #[cfg(not(feature = "resonance"))]
    {
        info!("🌊 Quillon Resonance Consensus: DISABLED (feature not enabled)");
    }

    // ========================================
    // v9.3.1: K-PARAMETER NETWORK HEALTH GAUGE (always-on, lightweight)
    // ========================================
    {
        use q_api_server::k_parameter_gauge::{KParameterEngine, KPhase, RawMetrics};
        use std::sync::atomic::Ordering as AtOrd;

        let k_state = state.k_parameter_state.clone();
        let k_submitted = state.mining_solutions_submitted.clone();
        let k_accepted = state.mining_solutions_accepted.clone();
        let k_bytes_in = state.p2p_bytes_in.clone();
        let k_bytes_out = state.p2p_bytes_out.clone();
        let k_peer_count = state.libp2p_peer_count.clone();
        let k_local_height = state.current_height_atomic.clone();
        let k_network_height = state.highest_network_height.clone();
        let k_pool = state.block_producer_pool.clone();

        tokio::spawn(async move {
            info!("📊 K-PARAM GAUGE: Starting (60s interval, v10.3.0 Enhanced K-Gauge)");
            let mut engine = KParameterEngine::new();
            let mut interval = tokio::time::interval(std::time::Duration::from_secs(60));
            interval.tick().await; // skip first immediate tick
            // Track the height at the start of each window for commitment depth (d_commit)
            let mut prev_window_height = k_local_height.load(AtOrd::Relaxed);

            loop {
                interval.tick().await;

                let current_local = k_local_height.load(AtOrd::Relaxed);
                let metrics = RawMetrics {
                    mining_submitted: k_submitted.load(AtOrd::Relaxed),
                    mining_accepted: k_accepted.load(AtOrd::Relaxed),
                    p2p_bytes_in: k_bytes_in.load(AtOrd::Relaxed),
                    p2p_bytes_out: k_bytes_out.load(AtOrd::Relaxed),
                    peer_count: k_peer_count
                        .as_ref()
                        .map(|p| p.load(AtOrd::Relaxed) as u64)
                        .unwrap_or(0),
                    local_height: current_local,
                    network_height: k_network_height.load(AtOrd::Relaxed),
                    // v10.3.0: Height at start of this window — blocks since then = d_commit
                    tip_height_at_window_start: prev_window_height,
                };
                // Update for next round
                prev_window_height = current_local;

                let (k, new_phase, prev_phase) = engine.compute_round(&metrics, &k_state);

                if new_phase != prev_phase {
                    match new_phase {
                        KPhase::Stable => {
                            tracing::warn!(
                                "📊 K-PARAM PHASE: {} → {} (K={:.4}) — relaxing parameters",
                                prev_phase.as_str(), new_phase.as_str(), k
                            );
                        }
                        KPhase::Approaching => {
                            tracing::warn!(
                                "📊 K-PARAM PHASE: {} → {} (K={:.4}) — tightening parameters",
                                prev_phase.as_str(), new_phase.as_str(), k
                            );
                        }
                        KPhase::Critical => {
                            tracing::error!(
                                "📊 K-PARAM PHASE: {} → CRITICAL (K={:.4}) — maximum protection",
                                prev_phase.as_str(), k
                            );
                        }
                    }

                    // Update max_solutions_per_block on all producers
                    let max_sol = k_state.tuned_max_solutions.load(AtOrd::Relaxed) as usize;
                    k_pool.set_max_solutions_per_block(max_sol);
                } else {
                    let k_enh = k_state.k_enhanced();
                    let omega = k_state.omega_node();
                    let lambda = k_state.lambda_commit();
                    let f_irr = f64::from_bits(k_state.f_irrev_bits.load(AtOrd::Relaxed));
                    tracing::info!(
                        "📊 K-GAUGE v10.3.0: K_base={:.4} K_enhanced={:.4} phase={} | Ω={:.3} Λ={:.3} f_irrev={:.1}% peers={} d_commit={}",
                        k, k_enh, new_phase.as_str(), omega, lambda, f_irr * 100.0,
                        metrics.peer_count, k_state.d_commit.load(AtOrd::Relaxed)
                    );
                }

                // Store zk-STARK commitment and phase proof
                k_state.store_zk_proof(
                    engine.last_zk_commitment().to_string(),
                    q_api_server::k_parameter_gauge::ZkPhaseProof {
                        commitment: engine.last_zk_phase_proof().commitment.clone(),
                        range_witness: engine.last_zk_phase_proof().range_witness.clone(),
                        challenge: engine.last_zk_phase_proof().challenge.clone(),
                        response: engine.last_zk_phase_proof().response.clone(),
                        verified: engine.last_zk_phase_proof().verified,
                    },
                );
            }
        });
        info!("✅ K-Parameter gauge spawned (60s periodic, lock-free reads, zk-STARK proofs)");
    }

    // ========================================
    // v10.3.0: SYSTEM HEALTH WATCHDOG (memory + P2P + cgroup diagnostics)
    // ========================================
    {
        let wd_peer_count = state.libp2p_peer_count.clone();
        let wd_height = state.current_height_atomic.clone();
        let wd_net_height = state.highest_network_height.clone();

        tokio::spawn(async move {
            info!("🏥 HEALTH WATCHDOG: Starting (300s interval, v10.3.0)");

            // Read cgroup memory.high at startup (once)
            let cgroup_high_bytes = tokio::fs::read_to_string("/sys/fs/cgroup/memory.high").await
                .ok()
                .and_then(|s| s.trim().parse::<u64>().ok())
                .unwrap_or(0);
            let cgroup_max_bytes = tokio::fs::read_to_string("/sys/fs/cgroup/memory.max").await
                .ok()
                .and_then(|s| s.trim().parse::<u64>().ok())
                .unwrap_or(0);
            let cgroup_high_gb = if cgroup_high_bytes > 0 { cgroup_high_bytes as f64 / 1_073_741_824.0 } else { 0.0 };
            let cgroup_max_gb = if cgroup_max_bytes > 0 { cgroup_max_bytes as f64 / 1_073_741_824.0 } else { 0.0 };

            info!("🏥 HEALTH WATCHDOG: cgroup memory.high={:.1}G memory.max={:.1}G", cgroup_high_gb, cgroup_max_gb);

            let mut interval = tokio::time::interval(std::time::Duration::from_secs(300));
            let mut last_height: u64 = 0;
            let mut stall_count: u32 = 0;
            let mut zero_peer_count: u32 = 0;

            loop {
                interval.tick().await;

                // --- Memory diagnostics ---
                let rss_kb = tokio::fs::read_to_string("/proc/self/statm").await
                    .ok()
                    .and_then(|s| {
                        let parts: Vec<&str> = s.split_whitespace().collect();
                        parts.get(1).and_then(|p| p.parse::<u64>().ok())
                    })
                    .unwrap_or(0) * 4; // pages to KB
                let rss_gb = rss_kb as f64 / 1_048_576.0;

                let cgroup_current = tokio::fs::read_to_string("/sys/fs/cgroup/memory.current").await
                    .ok()
                    .and_then(|s| s.trim().parse::<u64>().ok())
                    .unwrap_or(0);
                let cgroup_current_gb = cgroup_current as f64 / 1_073_741_824.0;

                let cgroup_events_high = tokio::fs::read_to_string("/sys/fs/cgroup/memory.events").await
                    .ok()
                    .and_then(|s| {
                        s.lines().find(|l| l.starts_with("high "))
                            .and_then(|l| l.split_whitespace().nth(1))
                            .and_then(|v| v.parse::<u64>().ok())
                    })
                    .unwrap_or(0);

                let pressure_pct = if cgroup_high_bytes > 0 {
                    (cgroup_current as f64 / cgroup_high_bytes as f64) * 100.0
                } else {
                    0.0
                };

                // --- P2P diagnostics ---
                let peers = wd_peer_count.as_ref()
                    .map(|p| p.load(std::sync::atomic::Ordering::Relaxed))
                    .unwrap_or(0);
                let height = wd_height.load(std::sync::atomic::Ordering::Relaxed);
                let net_height = wd_net_height.load(std::sync::atomic::Ordering::SeqCst);
                let height_gap = if net_height > height { net_height - height } else { 0 };

                // Stall detection
                if height == last_height && height > 0 {
                    stall_count += 1;
                } else {
                    stall_count = 0;
                }
                last_height = height;

                // Zero peer detection
                if peers == 0 {
                    zero_peer_count += 1;
                } else {
                    zero_peer_count = 0;
                }

                // --- Log level based on health ---
                // v10.9.19: when cgroup_high is 0 (unbounded), show "unbounded" rather than
                // "0.0G (0%)" to avoid the misleading-looking display in HEALTH logs.
                let cgroup_high_disp = if cgroup_high_bytes > 0 {
                    format!("{:.1}G ({:.0}%)", cgroup_high_gb, pressure_pct)
                } else {
                    "unbounded (no pressure metric)".to_string()
                };
                if pressure_pct > 90.0 || zero_peer_count >= 3 || stall_count >= 3 {
                    tracing::error!(
                        "🚨 HEALTH CRITICAL: RSS={:.1}G cgroup_current={:.1}G high={} high_events={} | peers={} height={} gap={} stall_count={} zero_peers_count={}",
                        rss_gb, cgroup_current_gb, cgroup_high_disp, cgroup_events_high,
                        peers, height, height_gap, stall_count, zero_peer_count
                    );
                } else if pressure_pct > 75.0 || peers < 3 || stall_count >= 1 {
                    tracing::warn!(
                        "⚠️  HEALTH WARNING: RSS={:.1}G cgroup={:.1}G/{:.1}G ({:.0}%) high_events={} | peers={} height={} gap={} stall={}",
                        rss_gb, cgroup_current_gb, cgroup_high_gb, pressure_pct, cgroup_events_high,
                        peers, height, height_gap, stall_count
                    );
                } else {
                    tracing::info!(
                        "🏥 HEALTH OK: RSS={:.1}G cgroup={:.1}G/{:.1}G ({:.0}%) high_events={} | peers={} height={} gap={}",
                        rss_gb, cgroup_current_gb, cgroup_high_gb, pressure_pct, cgroup_events_high,
                        peers, height, height_gap
                    );
                }

                // --- v10.3.0: Periodic cache cleanup (prevents unbounded memory growth) ---
                // Bug #1: DUNE_QUERY_CACHE grows forever — evict entries older than TTL
                let dune_before = DUNE_QUERY_CACHE.len();
                DUNE_QUERY_CACHE.retain(|_, (cached_at, _)| cached_at.elapsed().as_secs() < DUNE_CACHE_TTL_SECS);
                let dune_evicted = dune_before - DUNE_QUERY_CACHE.len();

                // Bug #2: BALANCE_AMOUNT_LIMITS grows forever — evict entries older than 5 minutes
                let bal_before = BALANCE_AMOUNT_LIMITS.len();
                BALANCE_AMOUNT_LIMITS.retain(|_, (_, window_start)| window_start.elapsed().as_secs() < 300);
                let bal_evicted = bal_before - BALANCE_AMOUNT_LIMITS.len();

                if dune_evicted > 0 || bal_evicted > 0 {
                    tracing::info!(
                        "🧹 CACHE CLEANUP: DUNE_QUERY_CACHE evicted {} (remaining {}), BALANCE_AMOUNT_LIMITS evicted {} (remaining {})",
                        dune_evicted, DUNE_QUERY_CACHE.len(), bal_evicted, BALANCE_AMOUNT_LIMITS.len()
                    );
                }
            }
        });
        info!("✅ System health watchdog spawned (300s periodic, cgroup-aware, cache cleanup)");
    }

    // ========================================
    // PHASE 1: DAG STATE SYNCHRONIZATION INFRASTRUCTURE
    // ========================================
    info!("🔄 Initializing DAG State Synchronization...");

    // 1. Initialize PeerRegistry for validator peer tracking
    let peer_registry = Arc::new(q_network::PeerRegistry::new(node_id));
    info!("✅ PeerRegistry initialized");

    // 2. Initialize PersistentChannelManager for dedicated Tor circuits (if Tor is available)
    let channel_manager = if let Some(tor_client) = &state.tor_client {
        let mgr = Arc::new(q_network::PersistentChannelManager::new(
            tor_client.clone(),
            node_id,
            24, // 24-hour circuit rotation
        ));
        info!("✅ PersistentChannelManager initialized with Tor circuits");
        Some(mgr)
    } else {
        warn!("⚠️  PersistentChannelManager skipped (no Tor client available)");
        None
    };

    // 3. Initialize DagSyncManager for full blockchain state synchronization
    if let Some(channel_mgr) = &channel_manager {
        let dag_sync = Arc::new(q_network::DagSyncManager::new(
            node_id,
            peer_registry.clone(),
            channel_mgr.clone(),
        ));

        state.dag_sync_manager = Some(dag_sync.clone());

        info!("✅ DagSyncManager initialized - full sync enabled");
        info!("   📦 Sync capabilities: DAG vertices, certificates, transactions");
        info!("   💰 Sync capabilities: wallet balances, smart contracts");
        info!("   🔗 Sync will trigger automatically on peer connection");
    } else {
        warn!("⚠️  DagSyncManager initialization skipped (requires Tor circuits)");
        info!("   Using fallback: direct peer communication without sync");
    }

    // ========================================
    // MINING SUBMISSION QUEUE - ASYNC PROCESSING
    // ========================================
    // ✅ v1.0.2-beta Layer 3 FIX: Bounded channel with backpressure
    // Prevents memory exhaustion from unbounded queue growth
    info!("⚡ Initializing mining submission async queue...");
    // ⚡ v8.9.0: Sharded mining pipeline — N parallel consumers for 1M+ TPS
    // Each shard is an independent mpsc channel with its own batch processor.
    // The HTTP handler round-robins across shards with spillover on full.
    // v9.1.7: Cap shards at 8 — more shards means more concurrent spawn_blocking calls
    // competing for the same CPU cores via rayon. 48 shards × rayon par_iter = thread explosion.
    // 8 shards with larger queues performs better: fewer context switches, better cache locality.
    // Each shard still uses rayon par_iter across ALL cores for VDF verification.
    let num_mining_shards = num_cpus::get().min(8).max(4);
    // v9.6.2: Reduced default from 1M to 50K — 1M buffers 9+ hours of submissions
    // which wastes hundreds of MB if channels fill during stalls. 50K = 27 min buffer at 30/s peak.
    // Override via Q_MINING_CHANNEL_CAPACITY env var.
    let total_capacity = std::env::var("Q_MINING_CHANNEL_CAPACITY")
        .ok()
        .and_then(|v| v.parse::<usize>().ok())
        .unwrap_or(50_000);
    let shard_capacity = (total_capacity / num_mining_shards).max(100); // Spread total capacity across shards
    let mut mining_txs: Vec<tokio::sync::mpsc::Sender<q_api_server::MiningSubmission>> = Vec::with_capacity(num_mining_shards);
    let mut mining_rxs: Vec<tokio::sync::mpsc::Receiver<q_api_server::MiningSubmission>> = Vec::with_capacity(num_mining_shards);
    for _shard_id in 0..num_mining_shards {
        let (tx, rx) = tokio::sync::mpsc::channel::<q_api_server::MiningSubmission>(shard_capacity);
        mining_txs.push(tx);
        mining_rxs.push(rx);
    }
    state.mining_submission_txs = Some(Arc::new(mining_txs));
    state.mining_shard_index = Some(Arc::new(std::sync::atomic::AtomicUsize::new(0)));
    // Also set legacy single tx as None (shards are active)
    state.mining_submission_tx = None;

    // v8.9.0: Miner stats aggregator channel (all shards → single 1Hz writer)
    let (miner_stats_tx, mut miner_stats_rx) = tokio::sync::mpsc::channel::<(String, f64, Option<String>, Option<String>)>(10_000);
    state.miner_stats_tx = Some(miner_stats_tx);

    // v8.9.0: SSE mining event aggregator channel (all shards → single 10Hz broadcaster)
    let (sse_mining_event_tx, mut sse_mining_event_rx) = tokio::sync::mpsc::channel::<q_api_server::SseMiningEvent>(10_000);
    state.sse_mining_event_tx = Some(sse_mining_event_tx);

    info!("✅ Mining pipeline initialized - {} shards × {} capacity = {} total (CPUs: {})",
          num_mining_shards, shard_capacity, num_mining_shards * shard_capacity, num_cpus::get());
    info!("   Non-blocking try_send() with round-robin + spillover (v8.9.0)");
    info!("   VDF verification on spawn_blocking (parallel CPU)");
    info!("   Stats aggregator at 1Hz, SSE aggregator at 10Hz");
    info!("   Sync gate rejects submissions when >10K blocks behind");

    // ========================================
    // 🚀 TURBO SYNC - Git-Inspired Fast Blockchain Synchronization
    // 50-250x faster sync speeds with parallel downloads and compression
    // ========================================
    info!("🚀 Initializing Turbo Sync (Git-inspired fast sync)...");

    // ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    // 🎯 v1.0.36-beta: SAFE ENV-DRIVEN TURBO SYNC CONFIG
    // ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    //
    // Defaults to v1.0.32 PROVEN working config (8 blocks/s with P2P)
    // Override ONLY via environment variables to avoid breaking P2P:
    //
    // Test Matrix (change ONE at a time!):
    // - Q_TURBO_PARALLEL_STREAMS=16  # Test parallel increase
    // - Q_TURBO_CHUNK_SIZE=2500      # Test chunk reduction
    // - Q_TURBO_COMPRESSION_LEVEL=1  # Test compression change
    // - Q_TURBO_CHUNK_TIMEOUT_SECS=30 # Test timeout reduction
    // - Q_BATCHED_WRITES=1           # Enable batched writes (after P2P stable)
    //
    // CRITICAL: Verify P2P sync works after EACH change!
    // If P2P falls back to HTTP, you broke something - revert that change!
    //
    let mut turbo_sync_config = q_storage::TurboSyncConfig::default();

    // 🎯 v1.0.36-beta: CPU-aware parallel streams (opt-in with Q_TURBO_PARALLEL_STREAMS=auto)
    turbo_sync_config.parallel_streams = match std::env::var("Q_TURBO_PARALLEL_STREAMS").ok().as_deref() {
        Some("auto") => {
            // Auto-detect optimal value based on CPU cores
            std::thread::available_parallelism()
                .map(|n| {
                    let cores = n.get();
                    // Use cores - 1 to reserve one core for gossipsub/heartbeat/block production
                    let optimal_streams = cores.saturating_sub(1).max(1);
                    info!("🎯 [AUTO] Detected {} CPU cores → using {} parallel streams (reserved 1 core)",
                          cores, optimal_streams);
                    optimal_streams
                })
                .unwrap_or(turbo_sync_config.parallel_streams) // Fallback to default
        }
        Some(val) => {
            // User specified a number
            val.parse().unwrap_or(turbo_sync_config.parallel_streams)
        }
        None => {
            // Not set - use safe default (8)
            turbo_sync_config.parallel_streams
        }
    };

    turbo_sync_config.chunk_size =
        env_u64("Q_TURBO_CHUNK_SIZE", turbo_sync_config.chunk_size);

    turbo_sync_config.compression_level =
        env_i32("Q_TURBO_COMPRESSION_LEVEL", turbo_sync_config.compression_level);

    // 🎯 v1.0.37-beta: ADAPTIVE CHUNK TIMEOUT (eliminates false timeouts)
    // Dynamically calculate timeout based on chunk size and compression level
    turbo_sync_config.chunk_timeout = if std::env::var("Q_TURBO_CHUNK_TIMEOUT_SECS").is_ok() {
        // User explicitly set it - use their value
        std::time::Duration::from_secs(
            env_u64("Q_TURBO_CHUNK_TIMEOUT_SECS", turbo_sync_config.chunk_timeout.as_secs())
        )
    } else {
        // Auto-calculate based on chunk size and compression
        let base_time = 30.0; // seconds for 5000 blocks at compression level 3
        let size_factor = turbo_sync_config.chunk_size as f64 / 5000.0;
        let compression_penalty = if turbo_sync_config.compression_level < 3 {
            1.5 // Faster compression = more CPU on server = more time needed
        } else {
            1.0
        };

        let calculated_timeout = (base_time * size_factor * compression_penalty).max(10.0);
        let timeout_secs = calculated_timeout as u64;

        info!("🎯 [ADAPTIVE] Calculated chunk_timeout: {}s (chunk_size: {}, compression: {})",
              timeout_secs, turbo_sync_config.chunk_size, turbo_sync_config.compression_level);

        std::time::Duration::from_secs(timeout_secs)
    };

    turbo_sync_config.enable_batched_writes =
        env_flag("Q_BATCHED_WRITES", turbo_sync_config.enable_batched_writes);

    // Log the ACTUAL config being used (critical for debugging)
    info!(
        "🎯 TurboSyncConfig: streams={} chunk_size={} compression_level={} timeout={:?} batched_writes={}",
        turbo_sync_config.parallel_streams,
        turbo_sync_config.chunk_size,
        turbo_sync_config.compression_level,
        turbo_sync_config.chunk_timeout,
        turbo_sync_config.enable_batched_writes,
    );

    // Warn if using non-default values
    if turbo_sync_config.parallel_streams != 8 {
        warn!("⚠️  Using non-default parallel_streams: {} (default: 8)",
              turbo_sync_config.parallel_streams);
    }
    if turbo_sync_config.chunk_size != 5000 {
        warn!("⚠️  Using non-default chunk_size: {} (default: 5000)",
              turbo_sync_config.chunk_size);
    }
    if turbo_sync_config.compression_level != 3 {
        warn!("⚠️  Using non-default compression_level: {} (default: 3)",
              turbo_sync_config.compression_level);
    }
    if turbo_sync_config.chunk_timeout.as_secs() != 60 {
        warn!("⚠️  Using non-default chunk_timeout: {:?} (default: 60s)",
              turbo_sync_config.chunk_timeout);
    }
    if turbo_sync_config.enable_batched_writes {
        info!("🚀 Batched writes ENABLED - expect 3-5x faster sync (if P2P stable)");
    } else {
        info!("⚠️  Batched writes DISABLED - using safe per-block writes");
    }

    // ========================================
    // TRUE P2P TURBO SYNC - Network Request Channel
    // Set up BEFORE creating Arc to avoid Arc::get_mut() failure
    // ========================================
    let (network_request_tx, mut network_request_rx) =
        tokio::sync::mpsc::unbounded_channel::<q_storage::NetworkRequest>();

    // Shared response map for tracking pending block pack requests
    // v6.0.10: Added Instant timestamp to enable TTL cleanup (prevents OOM from orphaned entries)
    let turbo_sync_response_map: Arc<
        tokio::sync::Mutex<
            std::collections::HashMap<
                String,
                (tokio::sync::oneshot::Sender<anyhow::Result<q_storage::BlockPack>>, std::time::Instant),
            >,
        >,
    > = Arc::new(tokio::sync::Mutex::new(std::collections::HashMap::new()));

    // Auto-promote Epsilon (quillon.xyz primary bootstrap) to supernode for 10x sync priority.
    // Dynamically fetches current peer ID — no hardcoded peer ID required.
    // Q_SUPERNODE_PEERS env var overrides if set explicitly.
    if turbo_sync_config.supernode_peers.is_empty() {
        match reqwest::Client::new()
            .get("https://quillon.xyz/api/v1/status")
            .timeout(std::time::Duration::from_secs(5))
            .send()
            .await
        {
            Ok(resp) => {
                if let Ok(body) = resp.text().await {
                    if let Ok(v) = serde_json::from_str::<serde_json::Value>(&body) {
                        if let Some(pid) = v.pointer("/data/peer_id").and_then(|x| x.as_str()) {
                            turbo_sync_config.supernode_peers.push(pid.to_string());
                            info!("🚀 [TURBO SYNC] Auto-promoted Epsilon to supernode: {} (10x priority)", pid);
                        }
                    }
                }
            }
            Err(_) => {
                info!("⚠️ [TURBO SYNC] Could not reach quillon.xyz for Epsilon peer ID — using default peer selection");
            }
        }
    }

    let mut turbo_sync_manager =
        q_storage::TurboSyncManager::new(state.storage_engine.clone(), turbo_sync_config);

    // Configure network channel BEFORE wrapping in Arc
    turbo_sync_manager.set_network_channel(network_request_tx.clone());
    info!("✅ TRUE P2P Turbo Sync network channel configured!");

    // 🎚️ v8.5.4: Share throttle mode atomic between AppState and TurboSyncManager
    // TUI sets it via AppState, sync loop reads it via TurboSyncManager — same Arc
    turbo_sync_manager.set_network_throttle_mode(state.network_throttle_mode.clone());
    let throttle_name = match state.network_throttle_mode.load(std::sync::atomic::Ordering::Relaxed) {
        0 => "Conservative", 1 => "Normal", _ => "Turbo",
    };
    info!("🎚️ [THROTTLE] Network throttle mode: {} (toggle with T in TUI)", throttle_name);

    let turbo_sync = Arc::new(turbo_sync_manager);
    state.turbo_sync = Some(turbo_sync.clone());

    // v10.9.47: AUTONOMOUS GAP HEAL — wire NetworkManager → TurboSync broadcast.
    // 1. Hydrate known_gaps from RocksDB-persisted entries (gaps detected in prior runs).
    // 2. Create broadcast channel (capacity 64 — handles bursts of new-peer discoveries).
    // 3. Lock libp2p_manager briefly to install the tx; install rx on turbo_sync.
    // 4. Spawn the handler task that applies Beta-trust policy + persists accepted gaps.
    // Once spawned, the user-facing Q_KNOWN_PERMANENT_GAPS env var is no longer needed:
    // peers declare gaps via the v10.9.41 protocol, the handler validates, persists,
    // and the next sync_to_height tick auto-advances past them via the v10.9.46
    // KNOWN-GAP check.
    if let Some(libp2p_manager_arc) = state.libp2p_discovery.as_ref() {
        let hydrated = turbo_sync.load_persisted_gaps().await;
        info!(
            "🚧 [KNOWN-GAP v10.9.47] Hydrated {} permanent gap(s) from RocksDB at startup",
            hydrated
        );
        let (gap_tx, gap_rx) = tokio::sync::broadcast::channel::<(u64, u64, libp2p::PeerId)>(64);
        turbo_sync.set_gap_advance_rx(gap_rx);
        {
            let mut mgr = libp2p_manager_arc.lock().await;
            mgr.set_gap_advance_tx(gap_tx);
        }
        turbo_sync.clone().spawn_gap_advance_handler();
        info!("🚧 [KNOWN-GAP v10.9.47] Autonomous gap-heal wired and active");
    } else {
        warn!(
            "🚧 [KNOWN-GAP v10.9.47] libp2p_discovery is None — autonomous gap-heal DISABLED. \
             Set Q_KNOWN_PERMANENT_GAPS env var to fall back to manual config."
        );
    }

    // v10.5.0 RC-3: Spawn gap-fill consumer — receives (first_gap, last_gap) from auto-repair.
    // Fetches the missing block range via P2P (libp2p block-pack) and stores each block in
    // RocksDB without touching the contiguous pointer (pointer advances on next integrity check).
    {
        let turbo_sync_gap = turbo_sync.clone();
        let mut gap_fill_rx = gap_fill_rx;
        tokio::spawn(async move {
            while let Some((first_gap, last_gap)) = gap_fill_rx.recv().await {
                warn!("🔧 [RC-3 GAP-FILL P2P] Dispatching P2P fetch for missing blocks {}-{}", first_gap, last_gap);
                if let Err(e) = turbo_sync_gap.fill_gap_p2p(first_gap, last_gap).await {
                    warn!("⚠️ [RC-3 GAP-FILL P2P] fetch for {}-{} failed: {}", first_gap, last_gap, e);
                }
            }
        });
    }

    // v10.8.1: Automatic checkpoint gap-fill — handles two cases:
    //  A) Fresh checkpoint application found gaps (checkpoint_gap_ranges populated above)
    //  B) Previous boot detected gaps and persisted them (loaded via load_checkpoint_pending_gaps,
    //     also returned when is_checkpoint_applied() is true)
    //  Q_RESCAN_CHECKPOINT_GAPS=1: Force a fresh gap scan of the full checkpoint range even if
    //     checkpoint is already applied and no ranges are stored — useful for nodes like Delta
    //     whose gaps predated v10.8.1.
    {
        let rescan_env = std::env::var("Q_RESCAN_CHECKPOINT_GAPS")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false);

        const CP_HEIGHT: u64 = 16_538_868; // CHECKPOINT_HEIGHT — hardcoded for gap detection

        let mut effective_gap_ranges: Vec<(u64, u64)> = if rescan_env
            && state.storage_engine.is_checkpoint_applied().await
        {
            warn!("🔍 [CHECKPOINT GAP-FILL] Q_RESCAN_CHECKPOINT_GAPS=1 — scanning checkpoint range for missing blocks...");
            let local_h = state.storage_engine
                .get_latest_qblock_height().await
                .unwrap_or(None)
                .unwrap_or(0);
            let mut ranges: Vec<(u64, u64)> = Vec::new();
            let mut gap_start: Option<u64> = None;
            let mut missing = 0u64;
            for h in (CP_HEIGHT + 1)..=local_h {
                match state.storage_engine.get_qblock_by_height(h).await {
                    Ok(Some(_)) => {
                        if let Some(gs) = gap_start.take() {
                            ranges.push((gs, h - 1));
                            warn!("🔍 [CHECKPOINT GAP-FILL] Gap detected: blocks {}-{} ({} blocks)", gs, h-1, h-gs);
                        }
                    }
                    _ => {
                        if gap_start.is_none() { gap_start = Some(h); }
                        missing += 1;
                    }
                }
            }
            if let Some(gs) = gap_start { ranges.push((gs, local_h)); }
            warn!(
                "🔍 [CHECKPOINT GAP-FILL] Scan complete: {} missing blocks in {} ranges (scanned {}→{})",
                missing, ranges.len(), CP_HEIGHT + 1, local_h
            );
            if !ranges.is_empty() {
                let _ = state.storage_engine.save_checkpoint_pending_gaps(&ranges).await;
            }
            ranges
        } else {
            checkpoint_gap_ranges
        };

        // v1.0.2 OPTION C-A: Two-phase sync.
        // Phase 1 (now): post-checkpoint operational gap-fill — runs immediately so the node
        //                reaches network tip fast (~3 min for the 1.34M post-checkpoint blocks).
        // Phase 2 (deferred): pre-checkpoint history backfill — kicks off automatically once
        //                Phase 1 reaches tip. Every node ends up with full history; we just
        //                sequence post-checkpoint first so the node is operational quickly.
        //
        // Previous behaviour: queued both ranges at startup, both compete for the same 8
        // in-flight network slots; pre-checkpoint chunks at heights 1-1000, 1000-2000, …
        // monopolize the queue's front and starve the forward-sync chunks. Observed: the
        // contiguous frontier stalled at ~25K for 30+ minutes while pre-checkpoint chunks
        // landed at random heights elsewhere. Two-phase removes the contention.
        let needs_pre_checkpoint_backfill = if state.storage_engine.is_checkpoint_applied().await {
            let has_genesis = state.storage_engine.get_qblock_by_height(1).await
                .ok().flatten().is_some();
            if !has_genesis {
                info!(
                    "🔭 [CHECKPOINT GAP-FILL Phase 2 queued] Pre-checkpoint history (blocks 1-{}) \
                     will be backfilled in the background once Phase 1 reaches network tip.",
                    CP_HEIGHT
                );
                true
            } else {
                false
            }
        } else {
            false
        };

        if !effective_gap_ranges.is_empty() && state.storage_engine.is_checkpoint_applied().await {
            let gap_sync   = turbo_sync.clone();
            let gap_store  = state.storage_engine.clone();
            let gap_bals   = state.wallet_balances.clone();
            let gap_supply = state.total_minted_supply.clone();
            let gap_ranges = effective_gap_ranges;
            tokio::spawn(async move {
                let total_missing: u64 = gap_ranges.iter().map(|(s, e)| e - s + 1).sum();
                warn!(
                    "🏁 [CHECKPOINT GAP-FILL] Starting: {} ranges / {} total missing blocks — \
                     waiting 90s for peer discovery before P2P fetch...",
                    gap_ranges.len(), total_missing
                );
                for (i, &(s, e)) in gap_ranges.iter().enumerate() {
                    warn!("   Range {}/{}: blocks {}-{} ({} blocks)", i+1, gap_ranges.len(), s, e, e-s+1);
                }

                tokio::time::sleep(tokio::time::Duration::from_secs(90)).await;

                // Check peer count before fetching
                {
                    let peer_count = gap_sync.peer_count_fast();
                    warn!("🔧 [CHECKPOINT GAP-FILL] Peers available: {} — beginning P2P fetch", peer_count);
                    if peer_count == 0 {
                        warn!("⚠️ [CHECKPOINT GAP-FILL] No peers yet — waiting another 60s...");
                        tokio::time::sleep(tokio::time::Duration::from_secs(60)).await;
                        let peer_count2 = gap_sync.peer_count_fast();
                        warn!("🔧 [CHECKPOINT GAP-FILL] Peers after extra wait: {}", peer_count2);
                    }
                }

                let mut ranges_filled = 0usize;
                let mut ranges_failed = 0usize;
                for &(start, end) in &gap_ranges {
                    warn!("🔧 [CHECKPOINT GAP-FILL] Fetching {}-{} ({} blocks) from P2P...", start, end, end-start+1);
                    match gap_sync.fill_gap_p2p(start, end).await {
                        Ok(()) => {
                            // Verify how many blocks were actually stored
                            let mut stored = 0u64;
                            for h in start..=end {
                                if gap_store.get_qblock_by_height(h).await.ok().flatten().is_some() {
                                    stored += 1;
                                }
                            }
                            warn!("   ✅ {}-{}: {}/{} blocks now in DB", start, end, stored, end-start+1);
                            ranges_filled += 1;
                        }
                        Err(e) => {
                            warn!("   ❌ {}-{}: P2P fetch failed: {}", start, end, e);
                            ranges_failed += 1;
                        }
                    }
                }

                warn!(
                    "🔧 [CHECKPOINT GAP-FILL] P2P phase done: {}/{} ranges filled, {} failed — \
                     re-applying transactions to fix balances...",
                    ranges_filled, gap_ranges.len(), ranges_failed
                );
                // Pre-checkpoint blocks (1..=CP_HEIGHT) don't need replay — the checkpoint
                // snapshot already has correct balances. Only replay post-checkpoint ranges.
                const CP_HEIGHT_REPLAY: u64 = 16_538_868;
                let post_cp_ranges: Vec<(u64, u64)> = gap_ranges.iter()
                    .filter(|&&(_, e)| e > CP_HEIGHT_REPLAY)
                    .copied()
                    .collect();
                if !post_cp_ranges.is_empty() {
                    if let Err(e) = gap_store.replay_gap_blocks(&post_cp_ranges, &gap_bals, &gap_supply).await {
                        warn!("⚠️ [CHECKPOINT GAP-FILL] Balance re-replay failed: {}", e);
                    } else {
                        warn!("✅ [CHECKPOINT GAP-FILL] Complete — balances corrected from recovered blocks.");
                    }
                } else {
                    warn!("✅ [CHECKPOINT GAP-FILL] Complete — pre-checkpoint history queued (balances already correct from checkpoint snapshot).");
                }
            });
        } else if effective_gap_ranges.is_empty() && state.storage_engine.is_checkpoint_applied().await {
            info!("✅ [CHECKPOINT GAP-FILL] No pending gap ranges — checkpoint balances are complete.");
        }

        // v1.0.2 OPTION C-A Phase 2: Pre-checkpoint history backfill.
        // Spawn a watcher that waits until forward sync (Phase 1) reaches network tip, then
        // queues the (1, CP_HEIGHT) range for download. This is what makes every node
        // archive-complete by default — same outcome as the old auto-queue-at-startup
        // behavior, just sequenced so Phase 1 isn't starved.
        //
        // "Reaches tip" = contiguous_height_atomic within READY_GAP blocks of the highest
        // height we've seen from any peer (current_height_atomic). Once that gate closes,
        // we kick off the 16.5M-block backfill which then runs at full turbo bandwidth
        // because Phase 1 is done.
        if needs_pre_checkpoint_backfill {
            let phase2_sync    = turbo_sync.clone();
            let phase2_storage = state.storage_engine.clone();
            let phase2_current = state.current_height_atomic.clone();
            let phase2_contig  = state.contiguous_height_atomic.clone();
            tokio::spawn(async move {
                const READY_GAP: u64 = 100;          // within 100 blocks of network tip
                const POLL_INTERVAL: u64 = 30;
                info!(
                    "🔭 [CHECKPOINT GAP-FILL Phase 2 watcher] Started — will fire when forward \
                     sync is within {} blocks of network tip.",
                    READY_GAP
                );

                let mut last_logged_gap: Option<u64> = None;
                // v10.9.19: require N consecutive ticks of gap ≤ READY_GAP before firing.
                // Without this, a single transient gap=0 reading (often when peer_count is
                // small and the one peer's announced height temporarily matches ours) fires
                // Phase 2 prematurely. With this, we need ≥ READY_TICKS_REQUIRED stable
                // readings — about 90 seconds of sustained convergence (3 × 30s polls).
                const READY_TICKS_REQUIRED: u32 = 3;
                let mut consecutive_ready_ticks: u32 = 0;
                loop {
                    tokio::time::sleep(std::time::Duration::from_secs(POLL_INTERVAL)).await;
                    let atom_max_seen = phase2_current.load(std::sync::atomic::Ordering::Relaxed);
                    let contiguous = phase2_contig.load(std::sync::atomic::Ordering::Relaxed);

                    // v1.0.2 FIX (#15): use peer-discovered tip, not just current_height_atomic.
                    // current_height_atomic plateaus at the height of blocks we've actually
                    // received; it doesn't reflect what peers have announced as their tip.
                    // For "are we at network tip?" the right source is peer_registry.max_height()
                    // (the highest height any peer has told us about). Take max of both —
                    // current_height_atomic catches local-stored tip, peer_registry catches
                    // network-known tip.
                    let peer_max = phase2_sync.get_enhanced_registry().await
                        .max_height()
                        .unwrap_or(0);
                    let effective_tip = peer_max.max(atom_max_seen);
                    if effective_tip == 0 {
                        continue; // no peers seen yet, no atom data yet
                    }
                    let gap = effective_tip.saturating_sub(contiguous);
                    let max_seen = effective_tip;

                    // Throttled progress logging — every order of magnitude or so.
                    let bucket = if gap > 10_000_000 { Some(10_000_000) }
                        else if gap > 1_000_000 { Some(1_000_000) }
                        else if gap > 100_000 { Some(100_000) }
                        else if gap > 10_000 { Some(10_000) }
                        else if gap > 1_000 { Some(1_000) }
                        else { Some(0) };
                    if bucket != last_logged_gap {
                        info!(
                            "🔭 [Phase 2 watcher] contiguous={} max_seen={} gap={} (waiting for gap ≤ {})",
                            contiguous, max_seen, gap, READY_GAP
                        );
                        last_logged_gap = bucket;
                    }

                    // v10.9.19: require N consecutive ready ticks before firing
                    if gap <= READY_GAP {
                        consecutive_ready_ticks = consecutive_ready_ticks.saturating_add(1);
                        if consecutive_ready_ticks < READY_TICKS_REQUIRED {
                            info!(
                                "🔭 [Phase 2 watcher] gap ≤ {} ({} consecutive ready ticks, need {}) — \
                                 holding fire to avoid transient-tip false positives.",
                                READY_GAP, consecutive_ready_ticks, READY_TICKS_REQUIRED
                            );
                            continue;
                        }
                    } else {
                        // Gap re-opened — reset the consecutive counter.
                        if consecutive_ready_ticks > 0 {
                            debug!(
                                "🔭 [Phase 2 watcher] gap reopened from ready state to {} — resetting consecutive counter",
                                gap
                            );
                            consecutive_ready_ticks = 0;
                        }
                    }
                    if gap <= READY_GAP {
                        info!(
                            "🚀 [Phase 2 START] Forward sync caught up (contiguous={}, max_seen={}, gap={}, after {} stable ticks). \
                             Kicking off pre-checkpoint backfill (blocks 1-{}).",
                            contiguous, max_seen, gap, consecutive_ready_ticks, CP_HEIGHT
                        );
                        // fill_gap_p2p routes >100K to fill_gap_via_turbo (Option B).
                        // After fix #16, that path probes peers for archive capability and returns
                        // Err if no archive peer reachable — in which case we retry on the next tick.
                        match phase2_sync.fill_gap_p2p(1, CP_HEIGHT).await {
                            Ok(()) => {
                                // Verify how many landed
                                let mut stored = 0u64;
                                let sample_step = 100_000u64;
                                let mut h = 1u64;
                                while h <= CP_HEIGHT {
                                    if phase2_storage.get_qblock_by_height(h).await
                                        .ok().flatten().is_some() {
                                        stored += 1;
                                    }
                                    h += sample_step;
                                }
                                let total_samples = (CP_HEIGHT / sample_step) + 1;
                                if stored < total_samples / 2 {
                                    warn!(
                                        "⚠️ [Phase 2] Coverage check failed: only {} of {} sampled \
                                         blocks present. Treating as partial completion — will retry on next tick.",
                                        stored, total_samples
                                    );
                                    continue;
                                }
                                info!(
                                    "✅ [Phase 2 DONE] Pre-checkpoint backfill complete \
                                     (sampled {} of {} blocks present).",
                                    stored, total_samples
                                );
                                break; // success — watcher's job done
                            }
                            Err(e) => {
                                warn!(
                                    "⚠️ [Phase 2] Backfill returned error: {} — will retry on next 30s tick.",
                                    e
                                );
                                continue;
                            }
                        }
                    }
                }
            });
        }
    }

    // v10.7.6 SYNC-006: Dedicated post-checkpoint balance replay task.
    // The old `now_synced && !was_synced` trigger in the adaptive sync loop is unreliable:
    // HEIGHT DECAY can create spurious sync_gap=0 events before all blocks are present, and
    // `continue` statements in the gap-fill path prevent the sync-complete block from being
    // reached. This task polls every 30s for a reliable completion signal and runs the
    // replay exactly once, guarded by a RocksDB flag so restarts skip it.
    {
        let replay_storage  = state.storage_engine.clone();
        let replay_balances = state.wallet_balances.clone();
        let replay_supply   = state.total_minted_supply.clone();
        tokio::spawn(async move {
            // Allow genesis/archive nodes to opt out via env var. Marks replay done permanently
            // so this skip persists across restarts without re-checking the env var.
            if std::env::var("Q_SKIP_BALANCE_REPLAY").ok().as_deref() == Some("1") {
                info!("✅ [SYNC-006] Q_SKIP_BALANCE_REPLAY=1 — genesis/archive node, marking replay done and skipping.");
                let _ = replay_storage.mark_balance_replay_done().await;
                return;
            }
            // Skip if checkpoint was not applied (non-checkpoint nodes need no replay).
            // This is a one-time decision per node — checkpoint-applied status does not
            // change at runtime, so an early return is safe.
            if !replay_storage.is_checkpoint_applied().await {
                info!("✅ [SYNC-006] Checkpoint not applied on this node (ran from genesis) — no balance replay needed.");
                return;
            }
            use q_storage::balance_checkpoint::CHECKPOINT_HEIGHT;
            // v1.0.2: Persistent polling loop. The done-flag is checked INSIDE the loop
            // (not as an outer early-return) so the admin reset endpoint can re-trigger
            // a replay on the next 30s tick without requiring a service restart.
            // After a successful replay we keep polling — if the flag is later cleared,
            // the next iteration will detect it and re-run.
            info!("🔁 [SYNC-006] Persistent replay watcher started — checks done-flag every 30s.");
            let mut already_logged_waiting = false;
            let mut already_logged_done = false;
            loop {
                tokio::time::sleep(tokio::time::Duration::from_secs(30)).await;
                // Done-flag check inside the loop: if a previous iteration marked done,
                // skip cheaply. If the admin endpoint clears the flag, we pick it up here.
                if replay_storage.is_balance_replay_done().await {
                    if !already_logged_done {
                        info!("✅ [SYNC-006] Replay marked done — idling (will re-run if admin reset clears the flag).");
                        already_logged_done = true;
                        already_logged_waiting = false;
                    }
                    continue;
                }
                // Flag cleared (or never set) — replay is eligible. Reset the "done" log
                // gate so the next completion logs again.
                already_logged_done = false;
                let latest = replay_storage.get_latest_qblock_height().await
                    .ok().flatten().unwrap_or(0);
                if latest <= CHECKPOINT_HEIGHT {
                    if !already_logged_waiting {
                        info!("🔭 [SYNC-006] Latest block {} ≤ checkpoint {} — waiting…", latest, CHECKPOINT_HEIGHT);
                        already_logged_waiting = true;
                    }
                    continue;
                }
                already_logged_waiting = false;
                info!("🏁 [SYNC-006] Chain at height {} — reindexing DAG blocks then starting replay.", latest);

                // v1.0.2 debug: snapshot wallet count + supply + balance_root BEFORE replay.
                // Pair with the post-replay snapshot below to see exactly what changed.
                let (pre_wallets, pre_supply, pre_root) = {
                    let balances = replay_storage.load_wallet_balances().await.unwrap_or_default();
                    let count = balances.len();
                    let total: u128 = balances.values().copied().sum();
                    let root = replay_storage.compute_balance_root_for_block().await.unwrap_or([0u8; 32]);
                    (count, total, root)
                };
                info!(
                    "📸 [SYNC-006 PRE] h={} wallets={} supply={} QUG balance_root={}",
                    latest,
                    pre_wallets,
                    pre_supply / 1_000_000_000_000_000_000_000_000u128,
                    hex::encode(&pre_root[..8])
                );

                // Pre-replay reindex: convert qblock:dag:{N}:{proposer} keys to qblock:height:{N}
                // so that get_qblock_any_format() can find all gossip-received blocks.
                let reindex_start = std::time::Instant::now();
                if let Err(e) = replay_storage.reindex_dag_blocks_to_height_keys().await {
                    warn!("⚠️ [SYNC-006] Pre-replay reindex failed: {} — replay may miss DAG-format blocks.", e);
                } else {
                    info!("🔁 [SYNC-006] Pre-replay reindex completed in {:?}", reindex_start.elapsed());
                }
                let replay_start = std::time::Instant::now();
                match replay_storage.replay_post_checkpoint_balances(&replay_balances, &replay_supply).await {
                    Ok(blocks_missing) => {
                        let total_range = latest.saturating_sub(CHECKPOINT_HEIGHT);
                        let miss_pct = if total_range > 0 {
                            blocks_missing * 100 / total_range
                        } else {
                            0
                        };
                        let max_miss_pct: u64 = std::env::var("Q_REPLAY_MISS_PCT_MAX")
                            .ok()
                            .and_then(|v| v.parse().ok())
                            .unwrap_or(1);
                        if miss_pct > max_miss_pct {
                            warn!("⚠️ [SYNC-006] Replay miss rate {}% ({}/{}) exceeds {}% threshold — \
                                   NOT marking done, will retry in 30s.", miss_pct, blocks_missing, total_range, max_miss_pct);
                            continue;
                        }
                        info!(
                            "✅ [SYNC-006] Replay complete in {:?} (miss rate {}%, missed {}/{}) — reloading in-memory balances from RocksDB.",
                            replay_start.elapsed(), miss_pct, blocks_missing, total_range
                        );
                        // Reload the in-memory map so live queries immediately reflect the replayed state.
                        if let Ok(persisted) = replay_storage.load_wallet_balances().await {
                            let count = persisted.len();
                            let mut bal = replay_balances.write().await;
                            for (addr, amt) in &persisted { bal.insert(*addr, *amt); }
                            let total: u128 = bal.values().sum();
                            drop(bal);
                            *replay_supply.write().await = total;

                            // v1.0.2 debug: POST snapshot — match against PRE snapshot above
                            // to see exactly what replay changed. balance_root delta is the
                            // single most useful number for cross-node comparison.
                            let post_root = replay_storage.compute_balance_root_for_block().await.unwrap_or([0u8; 32]);
                            let wallet_delta = count as i64 - pre_wallets as i64;
                            let supply_delta_qug = (total as i128 - pre_supply as i128)
                                / 1_000_000_000_000_000_000_000_000i128;
                            info!(
                                "📸 [SYNC-006 POST] h={} wallets={} ({:+}) supply={} QUG ({:+} QUG) balance_root={} (was {})",
                                latest,
                                count,
                                wallet_delta,
                                total / 1_000_000_000_000_000_000_000_000u128,
                                supply_delta_qug,
                                hex::encode(&post_root[..8]),
                                hex::encode(&pre_root[..8])
                            );
                            if post_root == pre_root {
                                info!("🟰 [SYNC-006] balance_root unchanged — no state divergence detected.");
                            } else {
                                warn!(
                                    "🔀 [SYNC-006] balance_root CHANGED — replay corrected state. \
                                     Compare {} (POST) against another node's hash at same height.",
                                    hex::encode(&post_root[..8])
                                );
                            }
                            info!("✅ [SYNC-006] In-memory balances updated: {} wallets, {} QUG",
                                  count, total / 1_000_000_000_000_000_000_000_000u128);
                        }
                        let _ = replay_storage.mark_balance_replay_done().await;
                    }
                    Err(e) => {
                        warn!("⚠️ [SYNC-006] Replay failed: {} — will retry in 30s.", e);
                        continue; // Retry next loop iteration
                    }
                }
                // No `break` — keep polling so admin reset (which clears the done-flag)
                // can re-trigger a replay on the next 30s tick.
            }
        });
    }

